import { lazy, Suspense, useEffect } from 'react'
import { BrowserRouter, Routes, Route } from 'react-router-dom'
import { QueryClient, QueryClientProvider } from '@tanstack/react-query'
import { Toaster, toast } from 'sonner'
import i18n from './i18n'
import { AuthProvider } from './context/AuthContext'
import ErrorBoundary from './components/ErrorBoundary'
import ProtectedRoute from './components/ProtectedRoute'
import RootLayout from './layouts/RootLayout'
import PageLoader from './components/PageLoader'

const LoginPage = lazy(() => import('./pages/LoginPage'))
const RegisterPage = lazy(() => import('./pages/RegisterPage'))
const ForgotPasswordPage = lazy(() => import('./pages/ForgotPasswordPage'))
const ResetPasswordPage = lazy(() => import('./pages/ResetPasswordPage'))
const VerifyEmailPage = lazy(() => import('./pages/VerifyEmailPage'))
const Dashboard = lazy(() => import('./pages/Dashboard'))
const ApplicationList = lazy(() => import('./pages/Applications/List'))
const ApplicationCreate = lazy(() => import('./pages/Applications/Create'))
const ApplicationDetail = lazy(() => import('./pages/Applications/Detail'))
const ProjectList = lazy(() => import('./pages/Projects/List'))
const ProjectCreate = lazy(() => import('./pages/Projects/Create'))
const ProjectDetail = lazy(() => import('./pages/Projects/Detail'))
const UserList = lazy(() => import('./pages/Users/List'))
const RoleList = lazy(() => import('./pages/Roles/List'))
const MyReviews = lazy(() => import('./pages/Committee/MyReviews'))
const CommitteeMeetings = lazy(() => import('./pages/Committee/Meetings'))
const MeetingDetail = lazy(() => import('./pages/Committee/MeetingDetail'))
const Committees = lazy(() => import('./pages/Committee/Committees'))
const CommitteeDetail = lazy(() => import('./pages/Committee/CommitteeDetail'))
const Notifications = lazy(() => import('./pages/Notifications'))
const RiskRegister = lazy(() => import('./pages/Safety/RiskRegister'))
const AdverseEvents = lazy(() => import('./pages/Safety/AdverseEvents'))
const RiskIncidents = lazy(() => import('./pages/Safety/RiskIncidents'))
const CorrectiveActions = lazy(() => import('./pages/Safety/CorrectiveActions'))
const SavedSearches = lazy(() => import('./pages/System/SavedSearches'))
const RegistryPage = lazy(() => import('./pages/Registry/RegistryPage'))
const ProfilePage = lazy(() => import('./pages/Profile/ProfilePage'))
const DocumentsPage = lazy(() => import('./pages/Documents/DocumentsPage'))
const ReportsPage = lazy(() => import('./pages/Reports/ReportsPage'))
const MessagesPage = lazy(() => import('./pages/Messages/MessagesPage'))
const AdminDashboard = lazy(() => import('./pages/Admin/AdminDashboard'))
const ReviewFormsPage = lazy(() => import('./pages/ReviewForms/ReviewFormsPage'))
const ESignaturesPage = lazy(() => import('./pages/ESignatures/ESignaturesPage'))
const ConsentTemplates = lazy(() => import('./pages/Admin/ConsentTemplates'))
const ConsentTemplateVersions = lazy(() => import('./pages/Admin/ConsentTemplateVersions'))
const NotificationChannels = lazy(() => import('./pages/Admin/NotificationChannels'))
const BackupSettings = lazy(() => import('./pages/Admin/BackupSettings'))
const ReferenceData = lazy(() => import('./pages/Admin/ReferenceData'))


const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 30 * 1000,
      retry: 1,
      refetchOnWindowFocus: false,
    },
    mutations: {
      onError: (err: any) => {
        const msg = err?.response?.data?.error || err?.message || 'An unexpected error occurred'
        if (err?.response?.status !== 401 && err?.response?.status !== 403) {
          toast.error(msg)
        }
      },
    },
  },
})

export default function App() {
  useEffect(() => {
    const updateDir = () => {
      const lang = i18n.language?.startsWith('ar') ? 'ar' : 'en'
      document.documentElement.lang = lang
      document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr'
    }
    updateDir()
    i18n.on('languageChanged', updateDir)
    return () => { i18n.off('languageChanged', updateDir) }
  }, [])

  return (
    <QueryClientProvider client={queryClient}>
      <ErrorBoundary>
      <BrowserRouter>
        <AuthProvider>
          <Toaster richColors position="top-right" />
          <Suspense fallback={<PageLoader />}>
          <Routes>
            <Route path="/login" element={<LoginPage />} errorElement={<ErrorBoundary />} />
            <Route path="/register" element={<RegisterPage />} errorElement={<ErrorBoundary />} />
            <Route path="/forgot-password" element={<ForgotPasswordPage />} errorElement={<ErrorBoundary />} />
            <Route path="/reset-password" element={<ResetPasswordPage />} errorElement={<ErrorBoundary />} />
            <Route path="/verify-email" element={<VerifyEmailPage />} errorElement={<ErrorBoundary />} />
            <Route element={<ProtectedRoute />}>
              <Route element={<RootLayout />} errorElement={<ErrorBoundary />}>
                <Route index element={<Dashboard />} />
                <Route path="/applications" element={<ApplicationList />} />
                <Route path="/applications/create" element={<ApplicationCreate />} />
                <Route path="/applications/:id" element={<ApplicationDetail />} />
                <Route path="/projects" element={<ProjectList />} />
                <Route path="/projects/create" element={<ProjectCreate />} />
                <Route path="/projects/:id" element={<ProjectDetail />} />
                <Route path="/users" element={<UserList />} />
                <Route path="/roles" element={<RoleList />} />
                <Route path="/committee/reviews" element={<MyReviews />} />
                <Route path="/committee/committees" element={<Committees />} />
                <Route path="/committee/committees/:id" element={<CommitteeDetail />} />
                <Route path="/committee/meetings" element={<CommitteeMeetings />} />
                <Route path="/committee/meetings/:id" element={<MeetingDetail />} />
                <Route path="/notifications" element={<Notifications />} />
                <Route path="/risk-register" element={<RiskRegister />} />
                <Route path="/safety/adverse-events" element={<AdverseEvents />} />
                <Route path="/safety/risk-incidents" element={<RiskIncidents />} />
                <Route path="/safety/corrective-actions" element={<CorrectiveActions />} />
                <Route path="/saved-searches" element={<SavedSearches />} />
                <Route path="/registry" element={<RegistryPage />} />
                <Route path="/profile" element={<ProfilePage />} />
                <Route path="/documents" element={<DocumentsPage />} />
                <Route path="/reports" element={<ReportsPage />} />
                <Route path="/messages" element={<MessagesPage />} />
                <Route path="/admin" element={<AdminDashboard />} />
                <Route path="/admin/notification-channels" element={<NotificationChannels />} />
                <Route path="/admin/backup" element={<BackupSettings />} />
                <Route path="/admin/reference-data" element={<ReferenceData />} />
                <Route path="/admin/consent-templates" element={<ConsentTemplates />} />
                <Route path="/admin/consent-templates/:id/versions" element={<ConsentTemplateVersions />} />
                <Route path="/review-forms" element={<ReviewFormsPage />} />
                <Route path="/e-signatures" element={<ESignaturesPage />} />
              </Route>
            </Route>
          </Routes>
          </Suspense>
        </AuthProvider>
      </BrowserRouter>
      </ErrorBoundary>
    </QueryClientProvider>
  )
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useState } from 'react'
import { useTranslation } from 'react-i18next'
import { toast } from 'sonner'
import api from '../api/client'
import { StatusBadge } from './StatusBadge'
import { Button } from './ui/button'
import { Card, CardContent, CardHeader, CardTitle } from './ui/card'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from './ui/dialog'
import { Label } from './ui/label'
import { Textarea } from './ui/textarea'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from './ui/select'
import { Badge } from './ui/badge'
import { ClipboardList, CheckCircle, AlertTriangle, XCircle, Edit3 } from 'lucide-react'

const CONSENT_STATUS_COLORS: Record<string, string> = {
  PENDING: 'bg-gray-100 text-gray-800',
  APPROVED: 'bg-green-100 text-green-800',
  MINOR_REVISION: 'bg-yellow-100 text-yellow-800',
  MAJOR_REVISION: 'bg-orange-100 text-orange-800',
  REJECTED: 'bg-red-100 text-red-800',
}

const DECISIONS = ['APPROVED', 'MINOR_REVISION', 'MAJOR_REVISION', 'REJECTED']

export default function ConsentTab({ applicationId, canAssign, canReview, reviewerId }: {
  applicationId: string | number
  canAssign?: boolean
  canReview?: boolean
  reviewerId?: number
}) {
  const { t } = useTranslation()
  const queryClient = useQueryClient()

  const [openAssign, setOpenAssign] = useState(false)
  const [openReview, setOpenReview] = useState<any>(null)
  const [selectedVersionId, setSelectedVersionId] = useState('')
  const [isRequired, setIsRequired] = useState(true)
  const [reviewDecision, setReviewDecision] = useState('APPROVED')
  const [reviewComment, setReviewComment] = useState('')

  const { data: consents, isLoading } = useQuery({
    queryKey: ['app-consents', applicationId],
    queryFn: () => api.get(`/committee/consent/application-consents/${applicationId}`).then(r => r.data.data),
    enabled: !!applicationId,
  })

  const { data: templates } = useQuery({
    queryKey: ['consent-templates'],
    queryFn: () => api.get('/committee/consent/templates').then(r => r.data.data),
  })

  const { data: allVersions } = useQuery({
    queryKey: ['all-consent-versions', templates],
    queryFn: async () => {
      if (!templates?.length) return []
      const results = await Promise.all(
        templates.map((t: any) =>
          api.get(`/committee/consent/templates/${t.id}/versions`).then(r => r.data.data)
        )
      )
      return results.flat().filter((v: any) => v.status === 'APPROVED')
    },
    enabled: !!templates?.length,
  })

  const assignMutation = useMutation({
    mutationFn: (body: any) => api.post('/committee/consent/application-consents', body),
    onSuccess: () => {
      toast.success(t('consent.consentAssigned'))
      queryClient.invalidateQueries({ queryKey: ['app-consents', applicationId] })
      setOpenAssign(false)
    },
    onError: (err: any) => toast.error(err.response?.data?.error || t('common.error')),
  })

  const reviewMutation = useMutation({
    mutationFn: (body: any) => api.post('/committee/consent/reviews', body),
    onSuccess: () => {
      toast.success(t('consent.reviewSubmitted'))
      queryClient.invalidateQueries({ queryKey: ['app-consents', applicationId] })
      setOpenReview(null); setReviewComment(''); setReviewDecision('APPROVED')
    },
    onError: (err: any) => toast.error(err.response?.data?.error || t('common.error')),
  })

  function handleAssign() {
    if (!selectedVersionId) return
    assignMutation.mutate({
      application_id: Number(applicationId),
      consent_version_id: Number(selectedVersionId),
      is_required: isRequired,
    })
  }

  function handleSubmitReview() {
    if (!openReview) return
    reviewMutation.mutate({
      application_consent_id: openReview.id,
      decision: reviewDecision,
      comment: reviewComment,
    })
  }

  if (isLoading) return <Card><CardContent className="p-6 text-center text-gray-500">{t('common.loading')}</CardContent></Card>

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold flex items-center gap-2">
          <ClipboardList className="w-5 h-5" />{t('consent.assignedTemplates')}
        </h3>
        {canAssign && (
          <Button size="sm" onClick={() => setOpenAssign(true)}>
            {t('consent.assignTemplate')}
          </Button>
        )}
      </div>

      {(!consents || consents.length === 0) ? (
        <p className="text-gray-500 text-sm">{t('consent.noTemplates')}</p>
      ) : (
        <div className="space-y-3">
          {consents.map((ac: any) => (
            <Card key={ac.id}>
              <CardContent className="p-4">
                <div className="flex items-start justify-between">
                  <div className="space-y-1">
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{ac.template_name_ar}</span>
                      <StatusBadge status={ac.status} colorMap={CONSENT_STATUS_COLORS} />
                      {ac.is_required ? (
                        <Badge variant="outline" className="text-xs">{t('consent.required')}</Badge>
                      ) : (
                        <Badge variant="outline" className="text-xs bg-gray-50">{t('consent.optional')}</Badge>
                      )}
                    </div>
                    <div className="text-sm text-gray-500">
                      {t('consent.versionNo')} {ac.version_no} · {t(`consent.${ac.language}`)} · {ac.template_code}
                    </div>
                    {ac.reviewer_name && (
                      <div className="text-sm text-gray-500">{t('risk.assessedBy')}: {ac.reviewer_name}</div>
                    )}
                  </div>
                  <div className="flex gap-2">
                    {canReview && (ac.status === 'PENDING' || ac.status === 'MINOR_REVISION' || ac.status === 'MAJOR_REVISION') && (
                      <Button size="sm" variant="outline" onClick={() => { setOpenReview(ac); setReviewDecision('APPROVED'); setReviewComment('') }}>
                        <Edit3 className="w-4 h-4 ml-1" />{t('consent.reviewConsent')}
                      </Button>
                    )}
                  </div>
                </div>

                {/* Review History */}
                {ac.review_comments && ac.review_comments.length > 0 && (
                  <div className="mt-3 pt-3 border-t space-y-2">
                    <span className="text-xs font-medium text-gray-500">{t('consent.reviewHistory')}</span>
                    {ac.review_comments.slice(0, 3).map((rc: any) => (
                      <div key={rc.id} className="text-sm bg-gray-50 rounded p-2">
                        <div className="flex items-center gap-2">
                          <DecisionIcon decision={rc.decision} />
                          <span className="font-medium">{rc.reviewer_name}</span>
                          <span className="text-xs text-gray-400">{new Date(rc.created_at).toLocaleDateString()}</span>
                        </div>
                        <p className="text-gray-600 mt-1">{rc.comment}</p>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      <Dialog open={openAssign} onOpenChange={setOpenAssign}>
        <DialogContent>
          <DialogHeader><DialogTitle>{t('consent.assignTemplate')}</DialogTitle></DialogHeader>
          <div className="grid gap-4 py-4">
            <div>
              <Label>{t('consent.consentType')}</Label>
              <Select value={selectedVersionId} onValueChange={setSelectedVersionId}>
                <SelectTrigger><SelectValue placeholder={t('common.select')} /></SelectTrigger>
                <SelectContent>
                  {allVersions?.map((v: any) => (
                    <SelectItem key={v.id} value={String(v.id)}>
                      {v.title} (v{v.version_no} · {t(`consent.${v.language}`)})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="flex items-center gap-2">
              <input type="checkbox" id="isRequired" checked={isRequired} onChange={e => setIsRequired(e.target.checked)} className="rounded" />
              <Label htmlFor="isRequired" className="mb-0">{t('consent.isRequired')}</Label>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setOpenAssign(false)}>{t('common.cancel')}</Button>
            <Button onClick={handleAssign}>{t('common.save')}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={!!openReview} onOpenChange={(v) => { if (!v) setOpenReview(null) }}>
        <DialogContent>
          <DialogHeader><DialogTitle>{t('consent.reviewConsent')}</DialogTitle></DialogHeader>
          {openReview && (
            <div className="space-y-4 py-4">
              <div className="text-sm">
                <span className="font-medium">{openReview.template_name_ar}</span>
                <span className="text-gray-500 ml-2">(v{openReview.version_no} · {t(`consent.${openReview.language}`)})</span>
              </div>
              <div>
                <Label>{t('consent.reviewDecision')}</Label>
                <Select value={reviewDecision} onValueChange={setReviewDecision}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    {DECISIONS.map(d => (
                      <SelectItem key={d} value={d}>
                        <div className="flex items-center gap-2">
                          <DecisionIcon decision={d} />
                          <span>{t(`consent.${d === 'APPROVED' ? 'approved' : d === 'MINOR_REVISION' ? 'minorRevision' : d === 'MAJOR_REVISION' ? 'majorRevision' : 'rejected'}`)}</span>
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label>{t('consent.reviewComment')}</Label>
                <Textarea value={reviewComment} onChange={e => setReviewComment(e.target.value)} rows={4} />
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setOpenReview(null)}>{t('common.cancel')}</Button>
            <Button onClick={handleSubmitReview}>{t('consent.submitReview')}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

function DecisionIcon({ decision }: { decision: string }) {
  switch (decision) {
    case 'APPROVED': return <CheckCircle className="w-4 h-4 text-green-600" />
    case 'MINOR_REVISION': return <AlertTriangle className="w-4 h-4 text-yellow-600" />
    case 'MAJOR_REVISION': return <AlertTriangle className="w-4 h-4 text-orange-600" />
    case 'REJECTED': return <XCircle className="w-4 h-4 text-red-600" />
    default: return null
  }
}

import { useState, useMemo, memo } from 'react'
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow
} from './ui/table'
import { Input } from './ui/input'
import { Search, ChevronLeft, ChevronRight, ArrowUpDown, ArrowUp, ArrowDown, Inbox } from 'lucide-react'
import { useTranslation } from 'react-i18next'

interface Column<T> {
  key: string
  label: string
  render?: (item: T) => React.ReactNode
  filterable?: boolean
  sortable?: boolean
}

interface DataTableProps<T> {
  columns: Column<T>[]
  data: T[]
  onRowClick?: (item: T) => void
  searchable?: boolean
  pageSize?: number
  emptyMessage?: string
  loading?: boolean
  searchValue?: string
  onSearchChange?: (value: string) => void
  sortKey?: string | null
  sortDir?: 'asc' | 'desc'
  onSortChange?: (key: string) => void
}

function DataTableInner<T extends Record<string, any>>({
  columns, data, onRowClick, searchable, pageSize = 20, emptyMessage, loading,
  searchValue: externalSearch, onSearchChange,
  sortKey: externalSortKey, sortDir: externalSortDir, onSortChange
}: DataTableProps<T>) {
  const { t } = useTranslation()
  const [internalSearch, setInternalSearch] = useState('')
  const search = externalSearch !== undefined ? externalSearch : internalSearch
  const setSearch = onSearchChange || setInternalSearch
  const [filters, setFilters] = useState<Record<string, string>>({})
  const [page, setPage] = useState(0)
  const isSortControlled = onSortChange !== undefined
  const [internalSortKey, setInternalSortKey] = useState<string | null>(null)
  const [internalSortDir, setInternalSortDir] = useState<'asc' | 'desc'>('asc')
  const sortKey = isSortControlled ? externalSortKey ?? null : internalSortKey
  const sortDir = isSortControlled ? externalSortDir ?? 'asc' : internalSortDir

  const filterOptions = useMemo(() => {
    const opts: Record<string, string[]> = {}
    columns.filter(c => c.filterable).forEach(col => {
      const values = new Set(data.map(item => String(item[col.key] ?? '')).filter(Boolean))
      opts[col.key] = Array.from(values).sort()
    })
    return opts
  }, [columns, data])

  const filtered = useMemo(() => {
    let result = data
    if (search) {
      const q = search.toLowerCase()
      result = result.filter(item =>
        columns.some(col => {
          const val = col.render ? stripTags(col.render(item)) : String(item[col.key] ?? '')
          return val.toLowerCase().includes(q)
        })
      )
    }
    Object.entries(filters).forEach(([key, value]) => {
      if (value) {
        result = result.filter(item => String(item[key] ?? '') === value)
      }
    })
    if (!isSortControlled && sortKey) {
      result = [...result].sort((a, b) => {
        const av = String(a[sortKey] ?? '')
        const bv = String(b[sortKey] ?? '')
        return sortDir === 'asc' ? av.localeCompare(bv) : bv.localeCompare(av)
      })
    }
    return result
  }, [data, search, filters, columns, sortKey, sortDir])

  const totalPages = Math.ceil(filtered.length / pageSize)
  const paged = filtered.slice(page * pageSize, (page + 1) * pageSize)

  function stripTags(node: React.ReactNode): string {
    if (typeof node === 'string') return node
    if (typeof node === 'number') return String(node)
    return ''
  }

  function handleSort(key: string) {
    if (isSortControlled) {
      onSortChange(key)
    } else {
      if (internalSortKey === key) {
        setInternalSortDir(d => d === 'asc' ? 'desc' : 'asc')
      } else {
        setInternalSortKey(key)
        setInternalSortDir('asc')
      }
      setPage(0)
    }
  }

  if (loading) {
    return (
      <div className="rounded-lg border">
        <Table>
          <TableHeader>
            <TableRow>
              {columns.map(col => (
                <TableHead key={col.key}>{col.label}</TableHead>
              ))}
            </TableRow>
          </TableHeader>
          <TableBody>
            {Array.from({ length: 5 }).map((_, i) => (
              <TableRow key={i}>
                {columns.map(col => (
                  <TableCell key={col.key}>
                    <div className="h-4 bg-slate-200 rounded animate-pulse w-3/4" />
                  </TableCell>
                ))}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
    )
  }

  return (
    <div>
      {(searchable || Object.keys(filterOptions).length > 0) && (
        <div className="flex flex-wrap items-center gap-2 mb-3">
          {searchable && (
            <div className="relative flex-1 max-w-xs">
              <Search className="absolute left-2.5 top-2.5 w-4 h-4 text-slate-400" />
              <Input
                placeholder={t('common.search')}
                value={search}
                onChange={e => { setSearch(e.target.value); setPage(0) }}
                className="pl-8 h-9 text-sm"
              />
            </div>
          )}
          {Object.entries(filterOptions).map(([key, options]) => (
            <select
              key={key}
              value={filters[key] || ''}
              onChange={e => { setFilters({ ...filters, [key]: e.target.value }); setPage(0) }}
              className="p-1.5 border rounded text-sm bg-white"
            >
              <option value="">{t('common.all')} {columns.find(c => c.key === key)?.label || key}</option>
              {options.map(opt => (
                <option key={opt} value={opt}>{opt}</option>
              ))}
            </select>
          ))}
        </div>
      )}

      <div className="rounded-lg border overflow-x-auto">
        <Table>
          <TableHeader>
            <TableRow>
              {columns.map((col) => (
                <TableHead key={col.key}
                  className={col.sortable ? 'cursor-pointer select-none' : ''}
                  onClick={() => col.sortable && handleSort(col.key)}
                >
                  <div className="flex items-center gap-1">
                    {col.label}
                    {col.sortable && (
                      sortKey === col.key
                        ? (sortDir === 'asc' ? <ArrowUp className="w-3 h-3" /> : <ArrowDown className="w-3 h-3" />)
                        : <ArrowUpDown className="w-3 h-3 text-slate-300" />
                    )}
                  </div>
                </TableHead>
              ))}
            </TableRow>
          </TableHeader>
          <TableBody>
            {paged.length === 0 ? (
              <TableRow>
                <TableCell colSpan={columns.length} className="text-center py-12">
                  <div className="flex flex-col items-center gap-2 text-muted-foreground">
                    <Inbox className="w-8 h-8" />
                    <p className="text-sm font-medium">{emptyMessage || t('dataTable.noRecords')}</p>
                  </div>
                </TableCell>
              </TableRow>
            ) : (
              paged.map((item, i) => (
                <TableRow key={item.id || i}
                  className={onRowClick ? 'cursor-pointer hover:bg-slate-50' : ''}
                  onClick={() => onRowClick?.(item)}>
                  {columns.map((col) => (
                    <TableCell key={col.key}>
                      {col.render ? col.render(item) : item[col.key]}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      {totalPages > 1 && (
        <div className="flex items-center justify-between mt-2 text-sm text-slate-500">
          <span>{t('dataTable.records', { count: filtered.length })}</span>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setPage(Math.max(0, page - 1))}
              disabled={page === 0}
              className="p-1 rounded hover:bg-slate-100 disabled:opacity-30"
            >
              <ChevronLeft className="w-4 h-4" />
            </button>
            <span>{t('dataTable.pageOf', { page: page + 1, total: totalPages })}</span>
            <button
              onClick={() => setPage(Math.min(totalPages - 1, page + 1))}
              disabled={page >= totalPages - 1}
              className="p-1 rounded hover:bg-slate-100 disabled:opacity-30"
            >
              <ChevronRight className="w-4 h-4" />
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

