        { key: 'type_code', labelKey: 'referenceData.code', type: 'text', required: true },
        { key: 'type_name_ar', labelKey: 'referenceData.nameAr', type: 'text', required: true },
        { key: 'type_name_en', labelKey: 'referenceData.nameEn', type: 'text' },
      ],
    },
    {
      key: 'committee-types',
      labelKey: 'referenceData.committeeTypes',
      apiPath: '/admin/reference-data/committee-types',
      columns: [
        { key: 'type_code', labelKey: 'referenceData.code' },
        { key: 'type_name', labelKey: 'referenceData.name' },
      ],
      formFields: [
        { key: 'type_code', labelKey: 'referenceData.code', type: 'text', required: true },
        { key: 'type_name', labelKey: 'referenceData.name', type: 'text', required: true },
        { key: 'description', labelKey: 'referenceData.description', type: 'textarea' },
      ],
    },
    {
      key: 'committee-roles',
      labelKey: 'referenceData.committeeRoles',
      apiPath: '/admin/reference-data/committee-roles',
      columns: [
        { key: 'role_code', labelKey: 'referenceData.code' },
        { key: 'role_name', labelKey: 'referenceData.name' },
      ],
      formFields: [
        { key: 'role_code', labelKey: 'referenceData.code', type: 'text', required: true },
        { key: 'role_name', labelKey: 'referenceData.name', type: 'text', required: true },
        { key: 'description', labelKey: 'referenceData.description', type: 'textarea' },
      ],
    },
    {
      key: 'notification-channels',
      labelKey: 'referenceData.notificationChannels',
      apiPath: '/admin/reference-data/notification-channels',
      columns: [
        { key: 'channel_code', labelKey: 'referenceData.code' },
        { key: 'channel_name', labelKey: 'referenceData.name' },
        { key: 'is_active', labelKey: 'referenceData.isActive', render: (i) => i.is_active ? '✓' : '✗' },
      ],
      formFields: [
        { key: 'channel_code', labelKey: 'referenceData.code', type: 'text', required: true },
        { key: 'channel_name', labelKey: 'referenceData.name', type: 'text', required: true },
      ],
    },
    {
      key: 'professions',
      labelKey: 'referenceData.professions',
      apiPath: '/admin/reference-data/professions',
      columns: [
        { key: 'code', labelKey: 'referenceData.code' },
        { key: 'name_ar', labelKey: 'referenceData.nameAr' },
        { key: 'name_en', labelKey: 'referenceData.nameEn' },
        { key: 'category', labelKey: 'referenceData.category' },
      ],
      formFields: [
        { key: 'code', labelKey: 'referenceData.code', type: 'text', required: true },
        { key: 'name_ar', labelKey: 'referenceData.nameAr', type: 'text', required: true },
        { key: 'name_en', labelKey: 'referenceData.nameEn', type: 'text' },
        { key: 'category', labelKey: 'referenceData.category', type: 'text' },
      ],
    },
  ]

  const [activeTab, setActiveTab] = useState(entities[0].key)
  const [showCreate, setShowCreate] = useState(false)
  const [editItem, setEditItem] = useState<any | null>(null)
  const [formData, setFormData] = useState<Record<string, any>>({})

  const activeEntity = entities.find(e => e.key === activeTab)!

  const { data: items, isLoading } = useQuery({
    queryKey: ['reference-data', activeTab],
    queryFn: () => api.get(activeEntity.apiPath).then(r => r.data.data || []),
  })

  const { data: institutionTypes } = useQuery({
    queryKey: ['reference-data', 'institution-types'],
    queryFn: () => api.get('/admin/reference-data/institution-types').then(r => r.data.data || []),
    enabled: activeTab === 'institutions',
  })

  const createMutation = useMutation({
    mutationFn: (body: any) => api.post(activeEntity.apiPath, body),
    onSuccess: () => { toast.success(t('common.created')); queryClient.invalidateQueries({ queryKey: ['reference-data', activeTab] }); setShowCreate(false); setFormData({}) },
    onError: (err: any) => toast.error(err.response?.data?.error || t('common.error')),
  })

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: number; data: any }) => api.put(`${activeEntity.apiPath}/${id}`, data),
    onSuccess: () => { toast.success(t('common.updated')); queryClient.invalidateQueries({ queryKey: ['reference-data', activeTab] }); setEditItem(null); setFormData({}) },
    onError: (err: any) => toast.error(err.response?.data?.error || t('common.error')),
  })

  const deleteMutation = useMutation({
    mutationFn: (id: number) => api.delete(`${activeEntity.apiPath}/${id}`),
    onSuccess: () => { toast.success(t('common.deleted')); queryClient.invalidateQueries({ queryKey: ['reference-data', activeTab] }) },
    onError: (err: any) => toast.error(err.response?.data?.error || t('common.error')),
  })

  function openCreate() {
    const defaults: Record<string, any> = {}
    activeEntity.formFields.forEach(f => { defaults[f.key] = f.type === 'number' ? 0 : '' })
    setFormData(defaults)
    setShowCreate(true)
    setEditItem(null)
  }

  function openEdit(item: any) {
    const vals: Record<string, any> = {}
    activeEntity.formFields.forEach(f => { vals[f.key] = item[f.key] ?? '' })
    setFormData(vals)
    setEditItem(item)
    setShowCreate(false)
  }

  function handleSave(e: React.FormEvent) {
    e.preventDefault()
    const payload = { ...formData }
    if (editItem) {
      updateMutation.mutate({ id: editItem.id, data: payload })
    } else {
      createMutation.mutate(payload)
    }
  }

  function handleDelete(item: any) {
    if (window.confirm(t('common.confirmDelete'))) {
      deleteMutation.mutate(item.id)
    }
  }

  function updateField(key: string, value: any) {
    setFormData(prev => ({ ...prev, [key]: value }))
  }

  const entityColumns = [
    ...activeEntity.columns.map(col => ({
      ...col,
      label: t(col.labelKey),
      render: col.render || ((i: any) => String(i[col.key] ?? '')),
    })),
    ...(canEdit ? [{
      key: 'actions' as string,
      label: '',
      render: (i: any) => (
        <div className="flex gap-1">
          <button onClick={() => openEdit(i)} className="text-slate-400 hover:text-blue-600 p-1"><Pencil className="w-3.5 h-3.5" /></button>
          <button onClick={() => handleDelete(i)} className="text-slate-400 hover:text-red-600 p-1"><Trash2 className="w-3.5 h-3.5" /></button>
        </div>
      ),
    }] : []),
  ]

  const inputClass = "w-full p-2 border rounded text-sm"
  const labelClass = "block text-sm font-medium mb-1"

  const activeFormFields = activeEntity.formFields.map(f => {
    if (f.key === 'institution_type_id' && activeTab === 'institutions') {
      return { ...f, options: (institutionTypes || []).map((t: any) => ({ label: t.name_ar || t.name_en, value: String(t.id) })) }
    }
    return f
  })

  return (
    <div>
      <h1 className="text-2xl font-bold mb-6">{t('referenceData.title')}</h1>

      <div className="flex flex-wrap gap-1 mb-4 border-b pb-2">
        {entities.map(e => (
          <button
            key={e.key}
            onClick={() => { setActiveTab(e.key); setShowCreate(false); setEditItem(null) }}
            className={`px-3 py-1.5 text-sm rounded-t transition-colors ${activeTab === e.key ? 'bg-blue-600 text-white' : 'text-slate-600 hover:bg-slate-100'}`}
          >
            {t(e.labelKey)}
          </button>
        ))}
      </div>

      <div className="mb-4">
        <button onClick={openCreate} className="flex items-center gap-1.5 bg-blue-600 text-white px-3 py-1.5 rounded text-sm hover:bg-blue-700">
          <Plus className="w-3.5 h-3.5" /> {t('referenceData.addNew')}
        </button>
      </div>

      {(showCreate || editItem) && (
        <div className="bg-white p-4 rounded-lg border mb-4 max-w-lg">
          <h2 className="font-semibold mb-3 text-sm">{editItem ? t('referenceData.edit') : t('referenceData.addNew')}</h2>
          <form onSubmit={handleSave} className="space-y-3">
            {activeFormFields.map(f => (
              <div key={f.key}>
                <label className={labelClass}>{t(f.labelKey)}{f.required ? ' *' : ''}</label>
                {f.type === 'select' ? (
                  <select value={String(formData[f.key] ?? '')} onChange={e => updateField(f.key, e.target.value)} className={inputClass} required={f.required}>
                    <option value="">--</option>
                    {(f.options || []).map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
                  </select>
                ) : f.type === 'textarea' ? (
                  <textarea value={formData[f.key] ?? ''} onChange={e => updateField(f.key, e.target.value)} className={inputClass} rows={3} />
                ) : f.type === 'number' ? (
                  <input type="number" value={formData[f.key] ?? 0} onChange={e => updateField(f.key, f.type === 'number' ? parseInt(e.target.value) : e.target.value)} className={inputClass} required={f.required} />
                ) : (
                  <input value={formData[f.key] ?? ''} onChange={e => updateField(f.key, e.target.value)} className={inputClass} required={f.required} />
                )}
              </div>
            ))}
            <div className="flex gap-2 pt-1">
              <button type="submit" disabled={createMutation.isPending || updateMutation.isPending}
                className="bg-blue-600 text-white px-4 py-1.5 rounded text-sm disabled:opacity-50">
                {(createMutation.isPending || updateMutation.isPending) ? t('common.saving') : t('common.save')}
              </button>
              <button type="button" onClick={() => { setShowCreate(false); setEditItem(null); setFormData({}) }}
                className="bg-slate-200 text-slate-700 px-4 py-1.5 rounded text-sm">{t('common.cancel')}</button>
            </div>
          </form>
        </div>
      )}

      <DataTable
        searchable
        loading={isLoading}
        columns={entityColumns}
        data={items || []}
        emptyMessage={t('referenceData.empty')}
      />
    </div>
  )
}

import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { useNavigate } from 'react-router-dom'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useTranslation } from 'react-i18next'
import { toast } from 'sonner'
import { z } from 'zod'
import api from '../../api/client'
import { applicationCreateSchema } from '../../lib/schemas'

type ApplicationFormData = z.input<typeof applicationCreateSchema>

export default function ApplicationCreate() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const queryClient = useQueryClient()
  const { register, handleSubmit, formState: { errors, isSubmitting } } = useForm<ApplicationFormData>({
    resolver: zodResolver(applicationCreateSchema),
    defaultValues: { project_id: '', application_type: 'INITIAL', target_committee_id: '' },
  })

  const { data: projects, isLoading: projectsLoading } = useQuery({
    queryKey: ['projects-dropdown'],
    queryFn: () => api.get('/core/projects').then((r) => r.data.data),
  })

  const { data: committees } = useQuery({
    queryKey: ['committees-dropdown'],
    queryFn: () => api.get('/committee/committees').then((r) => r.data.data),
  })

  const mutation = useMutation({
    mutationFn: (body: any) => api.post('/core/applications', body),
    onSuccess: () => { toast.success(t('applications.created')); queryClient.invalidateQueries({ queryKey: ['applications'] }); navigate('/applications') },
    onError: (err: any) => toast.error(err.response?.data?.error || t('applications.createFailed')),
  })

  function onSubmit(data: ApplicationFormData) {
    mutation.mutate(data)
  }

  const noProjects = !projectsLoading && projects && projects.length === 0

  return (
    <div className="max-w-lg">
      <h1 className="text-2xl font-bold mb-6">{t('applications.new')}</h1>
      <form onSubmit={handleSubmit(onSubmit)} className="bg-white p-6 rounded-lg shadow space-y-4">
        <div>
          <label className="block text-sm font-medium mb-1">{t('applications.project')}</label>
          {noProjects ? (
            <div className="p-3 bg-yellow-50 border border-yellow-200 rounded text-sm text-yellow-800 space-y-2">
              <p>{t('applications.noProjects')}</p>
              <a href="/projects/create" className="text-blue-600 hover:underline font-medium">{t('applications.createProject')}</a>
            </div>
          ) : (
            <select {...register('project_id')} className="w-full p-2 border rounded text-sm" disabled={projectsLoading}>
              <option value="">{t('applications.selectProject')}</option>
              {(projects || []).map((p: any) => (
                <option key={p.id} value={p.id}>{p.title_ar}</option>
              ))}
            </select>
          )}
          {errors.project_id && <p className="text-red-500 text-xs">{errors.project_id.message}</p>}
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">{t('applications.applicationType')}</label>
          <select {...register('application_type')} className="w-full p-2 border rounded text-sm">
            <option value="INITIAL">{t('applications.initialReview')}</option>
            <option value="AMENDMENT">{t('applications.amendment')}</option>
            <option value="RENEWAL">{t('applications.renewal')}</option>
            <option value="EXPEDITED">{t('applications.expedited')}</option>
          </select>
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">{t('applications.targetCommittee')}</label>
          <select {...register('target_committee_id')} className="w-full p-2 border rounded text-sm">
            <option value="">{t('applications.selectCommittee')}</option>
            {(committees || []).map((c: any) => (
              <option key={c.id} value={c.id}>{c.committee_name_ar}</option>
            ))}
          </select>
          {errors.target_committee_id && <p className="text-red-500 text-xs">{errors.target_committee_id.message}</p>}
        </div>
        <div className="flex gap-3">
          <button type="submit" disabled={mutation.isPending || isSubmitting}
            className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 text-sm disabled:opacity-50">
            {mutation.isPending ? t('applications.submitting') : t('common.submit')}
          </button>
          <button type="button" onClick={() => navigate('/applications')}
            className="bg-slate-200 text-slate-700 px-4 py-2 rounded hover:bg-slate-300 text-sm">
            {t('common.cancel')}
          </button>
        </div>
      </form>
    </div>
  )
}

import { useParams, useNavigate } from 'react-router-dom'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useState } from 'react'
import { useTranslation } from 'react-i18next'
import { toast } from 'sonner'
import { committees, members } from '../../sdk/domains/committee.sdk'
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card'
import { Button } from '../../components/ui/button'
import DataTable from '../../components/DataTable'
import { StatusBadge } from '../../components/StatusBadge'
import { PageSkeleton } from '../../components/LoadingSkeleton'
import {
  ArrowLeft, Users, Building2, Tag, CalendarDays, UserPlus, Trash2,
  Eye, CalendarPlus, Award, AlertTriangle, FileText,
  Plus
} from 'lucide-react'
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger,
} from '../../components/ui/dialog'
import api from '../../api/client'

type Tab = 'members' | 'details' | 'meetings'

export default function CommitteeDetail() {
  const { t } = useTranslation()
  const { id } = useParams()
  const navigate = useNavigate()
  const queryClient = useQueryClient()
  const [activeTab, setActiveTab] = useState<Tab>('members')
  const [addDialogOpen, setAddDialogOpen] = useState(false)
  const [selectedUserId, setSelectedUserId] = useState('')
  const [selectedRoleId, setSelectedRoleId] = useState('')
  const [memberDetailOpen, setMemberDetailOpen] = useState(false)
  const [selectedMember, setSelectedMember] = useState<any>(null)
  const [memberDetailTab, setMemberDetailTab] = useState<'terms' | 'qualifications' | 'conflicts'>('terms')
  const [meetingDialogOpen, setMeetingDialogOpen] = useState(false)
  const [meetingDate, setMeetingDate] = useState('')
  const [meetingLocation, setMeetingLocation] = useState('')

  const committeeId = Number(id)

  const { data: committee, isLoading } = useQuery({
    queryKey: ['committee', committeeId],
    queryFn: () => committees.getById(committeeId).then(r => r.data.data),
    enabled: !!committeeId,
  })

  const { data: memberList, isLoading: membersLoading } = useQuery({
    queryKey: ['committee-members', committeeId],
    queryFn: () => members.listByCommittee(committeeId).then(r => r.data.data),
    enabled: !!committeeId,
  })

  const { data: meetingsList } = useQuery({
    queryKey: ['committee-meetings', committeeId],
    queryFn: () => api.get(`/committee/meetings/committee/${committeeId}`).then(r => r.data.data),
    enabled: !!committeeId,
  })

  const { data: committeeRoles } = useQuery({
    queryKey: ['committee-roles'],
    queryFn: () => committees.listRoles().then(r => r.data.data),
  })

  const { data: users } = useQuery({
    queryKey: ['users'],
    queryFn: () => api.get('/security/users').then(r => r.data.data),
  })

  const { data: memberTerms } = useQuery({
    queryKey: ['member-terms', selectedMember?.id],
    queryFn: () => members.getTerms(selectedMember.id).then(r => r.data.data),
    enabled: !!selectedMember && memberDetailOpen,
  })

  const { data: memberQualifications } = useQuery({
    queryKey: ['member-qualifications', selectedMember?.id],
    queryFn: () => members.getQualifications(selectedMember.id).then(r => r.data.data),
    enabled: !!selectedMember && memberDetailOpen,
  })

  const { data: memberConflicts } = useQuery({
    queryKey: ['member-conflicts', selectedMember?.id],
    queryFn: () => members.getConflicts(selectedMember.id).then(r => r.data.data),
    enabled: !!selectedMember && memberDetailOpen,
  })

  const addMember = useMutation({
    mutationFn: () => {
      const payload: { user_id: number; role_id?: number } = { user_id: Number(selectedUserId) }
      const roleId = Number(selectedRoleId)
      if (roleId > 0) payload.role_id = roleId
      return members.add(committeeId, payload)
    },
    onSuccess: () => {
      toast.success(t('committeeDetail.memberAdded'))
      queryClient.invalidateQueries({ queryKey: ['committee-members'] })
      setAddDialogOpen(false)
      setSelectedUserId('')
      setSelectedRoleId('')
    },
    onError: (err: any) => {
      toast.error(err?.response?.data?.error || err.message)
    },
  })

  const removeMember = useMutation({
    mutationFn: (memberId: number) => members.remove(committeeId, memberId),
    onSuccess: () => {
      toast.success(t('committeeDetail.memberRemoved'))
      queryClient.invalidateQueries({ queryKey: ['committee-members'] })
    },
    onError: (err: any) => {
      toast.error(err?.response?.data?.error || err.message)
    },
  })

  const updateRole = useMutation({
    mutationFn: ({ memberId, role_id }: { memberId: number; role_id: number }) =>
      members.updateRole(committeeId, memberId, { role_id }),
    onSuccess: () => {
      toast.success(t('committeeDetail.roleUpdated'))
      queryClient.invalidateQueries({ queryKey: ['committee-members'] })
    },
    onError: (err: any) => {
      toast.error(err?.response?.data?.error || err.message)
    },
  })

  const createMeeting = useMutation({
    mutationFn: () =>
      api.post('/committee/meetings', {
        committee_id: committeeId,
        meeting_date: meetingDate,
        location: meetingLocation || undefined,
      }),
    onSuccess: () => {
      toast.success(t('meetings.created'))
      queryClient.invalidateQueries({ queryKey: ['committee-meetings'] })
      setMeetingDialogOpen(false)
      setMeetingDate('')
      setMeetingLocation('')
    },
    onError: (err: any) => {
      toast.error(err?.response?.data?.error || err.message)
    },
  })

  const addTerm = useMutation({
    mutationFn: (data: any) => members.addTerm(selectedMember!.id, data),
    onSuccess: () => {
      toast.success('Term added')
      queryClient.invalidateQueries({ queryKey: ['member-terms'] })
    },
    onError: (err: any) => toast.error(err?.response?.data?.error || err.message),
  })

  const addQualification = useMutation({
    mutationFn: (data: any) => members.addQualification(selectedMember!.id, data),
    onSuccess: () => {
      toast.success('Qualification added')
      queryClient.invalidateQueries({ queryKey: ['member-qualifications'] })
    },
    onError: (err: any) => toast.error(err?.response?.data?.error || err.message),
  })

  const declareConflict = useMutation({
    mutationFn: (data: any) => members.declareConflict(selectedMember!.id, data),
    onSuccess: () => {
      toast.success('Conflict declared')
      queryClient.invalidateQueries({ queryKey: ['member-conflicts'] })
    },
    onError: (err: any) => toast.error(err?.response?.data?.error || err.message),
  })

  if (isLoading) return <PageSkeleton />
  if (!committee) return <p className="text-red-500">{t('committeeDetail.notFound')}</p>

  const tabs: { key: Tab; label: string; icon: React.ComponentType<{ className?: string }> }[] = [
    { key: 'members', label: t('committees.members'), icon: Users },
    { key: 'details', label: t('committeeDetail.details'), icon: Building2 },
    { key: 'meetings', label: t('meetings.title'), icon: CalendarDays },
  ]

  const handleRoleChange = (memberId: number, role_id: string) => {
    if (role_id) updateRole.mutate({ memberId, role_id: Number(role_id) })
  }

  const memberColumns = [
    { key: 'display_name', label: t('committeeDetail.memberName'), sortable: true },
    { key: 'username', label: t('committeeDetail.memberUsername') },
    {
      key: 'role_name', label: t('committeeDetail.role'), render: (m: any) => (
        <select
          value={m.role_id ?? ''}
          onChange={e => handleRoleChange(m.id, e.target.value)}
          className="text-xs p-1 border rounded bg-white"
        >
          <option value="">{t('committeeDetail.noRole')}</option>
          {(committeeRoles || []).map((r: any) => (
            <option key={r.id} value={String(r.id)}>{r.role_name}</option>
          ))}
        </select>
      ),
    },
    {
      key: 'is_active', label: t('common.status'), render: (m: any) => (
        <StatusBadge status={m.is_active ? 'ACTIVE' : 'INACTIVE'} />
      ),
    },
    {
      key: 'actions', label: '', render: (m: any) => (
        <div className="flex items-center gap-1">
          <Button variant="ghost" size="sm" onClick={() => { setSelectedMember(m); setMemberDetailOpen(true) }} className="text-slate-400 hover:text-blue-600">
            <Eye className="w-4 h-4" />
          </Button>
          <Button variant="ghost" size="sm" onClick={(e) => { e.stopPropagation(); removeMember.mutate(m.id) }} className="text-red-500 hover:text-red-700">
            <Trash2 className="w-4 h-4" />
          </Button>
        </div>
      ),
    },
  ]

  return (
    <div>
      <button onClick={() => navigate('/committee/committees')} className="flex items-center gap-1 text-sm text-slate-500 hover:text-slate-700 mb-4">
        <ArrowLeft className="w-4 h-4" /> {t('committeeDetail.back')}
      </button>

      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold">{committee.committee_name_ar}</h1>
          <p className="text-sm text-slate-500">{committee.committee_code}</p>
        </div>
        <StatusBadge status={committee.is_active ? 'ACTIVE' : 'INACTIVE'} />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <Card>
          <CardContent className="flex items-center gap-3 p-4">
            <div className="bg-slate-100 p-2 rounded"><Building2 className="w-5 h-5 text-slate-600" /></div>
            <div>
              <p className="text-xs text-slate-500">{t('committees.institution')}</p>
              <p className="text-sm font-medium">{committee.institution_name || '\u2014'}</p>
            </div>
          </CardContent>
        </Card>
        <Card>
