import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useState } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { useTranslation } from 'react-i18next'
import { useNavigate } from 'react-router-dom'
import { toast } from 'sonner'
import api from '../../api/client'
import DataTable from '../../components/DataTable'
import { Plus, Pencil } from 'lucide-react'
import { usePermission } from '../../hooks/usePermission'
import { z } from 'zod'

const committeeSchema = z.object({
  committee_code: z.string({ message: 'Code is required' }).min(1),
  committee_name_ar: z.string({ message: 'Arabic name is required' }).min(1),
  committee_name_en: z.string().optional().default(''),
  institution_id: z.string({ message: 'Institution is required' }).min(1),
  committee_type_id: z.string({ message: 'Type is required' }).min(1),
  is_active: z.boolean().optional().default(true),
})

type CommitteeFormData = z.input<typeof committeeSchema>

export default function Committees() {
  const { t } = useTranslation()
  const queryClient = useQueryClient()
  const navigate = useNavigate()
  const [showCreate, setShowCreate] = useState(false)
  const [editId, setEditId] = useState<number | null>(null)
  const canCreate = usePermission('user.create')
  const canUpdate = usePermission('user.update')

  const { register, handleSubmit, reset, formState: { errors } } = useForm<CommitteeFormData>({
    resolver: zodResolver(committeeSchema),
    defaultValues: { committee_code: '', committee_name_ar: '', committee_name_en: '', institution_id: '', committee_type_id: '', is_active: true },
  })

  const editForm = useForm<any>({
    defaultValues: { committee_name_ar: '', committee_name_en: '', institution_id: '', committee_type_id: '', is_active: true },
  })

  const { data: committees, isLoading } = useQuery({
    queryKey: ['committees'],
    queryFn: () => api.get('/committee/committees').then(r => r.data.data),
  })

  const { data: institutions } = useQuery({
    queryKey: ['institutions'],
    queryFn: () => api.get('/reference/institutions-registry').then(r => r.data.data || []),
  })

  const { data: committeeTypes } = useQuery({
    queryKey: ['committee-types'],
    queryFn: () => api.get('/committee/committees/committee-types').then(r => r.data.data || []),
  })

  const createMutation = useMutation({
    mutationFn: (body: any) => api.post('/committee/committees', body),
    onSuccess: () => { toast.success(t('committees.created')); queryClient.invalidateQueries({ queryKey: ['committees'] }); setShowCreate(false); reset() },
    onError: (err: any) => toast.error(err.response?.data?.error || t('committees.createFailed')),
  })

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: number; data: any }) => api.put(`/committee/committees/${id}`, data),
    onSuccess: () => { toast.success(t('committees.updated')); queryClient.invalidateQueries({ queryKey: ['committees'] }); setEditId(null) },
    onError: (err: any) => toast.error(err.response?.data?.error || t('committees.updateFailed')),
  })

  function openEdit(c: any) {
    editForm.reset({
      committee_name_ar: c.committee_name_ar || '',
      committee_name_en: c.committee_name_en || '',
      institution_id: c.institution_id ? String(c.institution_id) : '',
      committee_type_id: c.committee_type_id ? String(c.committee_type_id) : '',
      is_active: c.is_active ?? true,
    })
    setEditId(c.id)
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold">{t('committees.title')}</h1>
        {canCreate && (
          <button onClick={() => setShowCreate(!showCreate)}
            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 text-sm">
            <Plus className="w-4 h-4" /> {t('committees.new')}
          </button>
        )}
      </div>

      {editId && (
        <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center" onClick={() => setEditId(null)}>
          <div className="bg-white rounded-lg p-6 max-w-lg w-full mx-4 shadow-xl" onClick={e => e.stopPropagation()}>
            <h2 className="font-semibold mb-4">{t('committees.edit')}</h2>
            <form onSubmit={editForm.handleSubmit((data) => updateMutation.mutate({ id: editId, data }))} className="space-y-3">
              <div className="grid grid-cols-2 gap-3">
                <input placeholder={t('committees.nameAr')} {...editForm.register('committee_name_ar')} className="p-2 border rounded text-sm" />
                <input placeholder={t('committees.nameEn')} {...editForm.register('committee_name_en')} className="p-2 border rounded text-sm" />
              </div>
              <select {...editForm.register('institution_id')} className="w-full p-2 border rounded text-sm">
                <option value="">{t('committees.selectInstitution')}</option>
                {(institutions || []).map((i: any) => <option key={i.id} value={String(i.id)}>{i.name_ar || i.name_en}</option>)}
              </select>
              <div className="grid grid-cols-2 gap-3">
                <select {...editForm.register('committee_type_id')} className="p-2 border rounded text-sm">
                  <option value="">{t('committees.selectType')}</option>
                  {(committeeTypes || []).map((ct: any) => <option key={ct.id} value={String(ct.id)}>{ct.type_name}</option>)}
                </select>
                <label className="flex items-center gap-2 text-sm">
                  <input type="checkbox" {...editForm.register('is_active')} />
                  {t('committees.active')}
                </label>
              </div>
              <div className="flex gap-3">
                <button type="submit" disabled={updateMutation.isPending} className="bg-blue-600 text-white px-4 py-2 rounded text-sm disabled:opacity-50">
                  {updateMutation.isPending ? t('common.saving') : t('common.save')}
                </button>
                <button type="button" onClick={() => setEditId(null)} className="bg-slate-200 text-slate-700 px-4 py-2 rounded text-sm">{t('common.cancel')}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showCreate && (
        <div className="bg-white p-6 rounded-lg shadow mb-6 max-w-lg">
          <h2 className="font-semibold mb-4">{t('committees.create')}</h2>
          <form onSubmit={handleSubmit((data) => createMutation.mutate(data))} className="space-y-3">
            <div className="grid grid-cols-2 gap-3">
              <div><input placeholder={t('committees.codePlaceholder')} {...register('committee_code')} className="w-full p-2 border rounded text-sm" />{errors.committee_code && <p className="text-red-500 text-xs">{errors.committee_code.message}</p>}</div>
              <div><input placeholder={t('committees.nameAr')} {...register('committee_name_ar')} className="w-full p-2 border rounded text-sm" />{errors.committee_name_ar && <p className="text-red-500 text-xs">{errors.committee_name_ar.message}</p>}</div>
            </div>
            <input placeholder={t('committees.nameEn')} {...register('committee_name_en')} className="w-full p-2 border rounded text-sm" />
            <div className="grid grid-cols-2 gap-3">
              <select {...register('institution_id')} className="p-2 border rounded text-sm">
                <option value="">{t('committees.selectInstitution')}</option>
                {(institutions || []).map((i: any) => <option key={i.id} value={String(i.id)}>{i.name_ar || i.name_en}</option>)}
              </select>
              <select {...register('committee_type_id')} className="p-2 border rounded text-sm">
                <option value="">{t('committees.selectType')}</option>
                {(committeeTypes || []).map((ct: any) => <option key={ct.id} value={String(ct.id)}>{ct.type_name}</option>)}
              </select>
            </div>
            <div className="flex gap-3">
              <button type="submit" disabled={createMutation.isPending} className="bg-blue-600 text-white px-4 py-2 rounded text-sm disabled:opacity-50">
                {createMutation.isPending ? t('common.creating') : t('common.create')}
              </button>
              <button type="button" onClick={() => setShowCreate(false)} className="bg-slate-200 text-slate-700 px-4 py-2 rounded text-sm">{t('common.cancel')}</button>
            </div>
          </form>
        </div>
      )}

      <DataTable
        searchable
        loading={isLoading}
        onRowClick={(c: any) => navigate(`/committee/committees/${c.id}`)}
        columns={[
          { key: 'committee_code', label: t('committees.code'), sortable: true },
          { key: 'committee_name_ar', label: t('committees.nameAr'), sortable: true },
          { key: 'committee_name_en', label: t('committees.nameEn') },
          { key: 'committee_type_name', label: t('committees.type'), filterable: true },
          { key: 'institution_name', label: t('committees.institution'), sortable: true },
          { key: 'member_count', label: t('committees.members') },
          ...(canUpdate ? [{ key: 'actions' as string, label: '', render: (i: any) => <button onClick={(e) => { e.stopPropagation(); openEdit(i) }} className="text-slate-400 hover:text-blue-600"><Pencil className="w-4 h-4" /></button> }] : []),
        ]}
        data={committees || []}
        emptyMessage={t('committees.empty')}
      />
    </div>
  )
}

import { useParams, useNavigate } from 'react-router-dom'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useState } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { useTranslation } from 'react-i18next'
import { toast } from 'sonner'
import api from '../../api/client'
import { useAuth } from '../../context/AuthContext'
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card'
import { Button } from '../../components/ui/button'
import { Input } from '../../components/ui/input'
import { StatusBadge } from '../../components/StatusBadge'
import { meetingAgendaSchema, agendaItemSchema, attendanceSchema, minutesSchema, votingSessionSchema } from '../../lib/schemas'
import { z } from 'zod'
import { ArrowLeft, CalendarDays, FileText, UserCheck, MessageSquare, Vote } from 'lucide-react'
import { PageSkeleton } from '../../components/LoadingSkeleton'

export default function MeetingDetail() {
  const { t } = useTranslation()
  const { id } = useParams()
  const navigate = useNavigate()
  const { user } = useAuth()
  const queryClient = useQueryClient()
  const canEdit = user?.roles?.some(r => ['ETHICS_ADMIN', 'COMMITTEE_CHAIR', 'SUPER_ADMIN'].includes(r))

  const { data: meeting, isLoading } = useQuery({
    queryKey: ['meeting', id],
    queryFn: () => api.get(`/committee/meetings/${id}`).then(r => r.data.data),
    enabled: !!id,
  })

  const { data: agenda } = useQuery({
    queryKey: ['meeting-agenda', id],
    queryFn: () => api.get(`/committee/meetings/${id}/agenda`).then(r => r.data.data),
    enabled: !!id,
  })

  const { data: attendance } = useQuery({
    queryKey: ['meeting-attendance', id],
    queryFn: () => api.get(`/committee/meetings/${id}/attendance`).then(r => r.data.data),
    enabled: !!id,
  })

  const { data: minutes } = useQuery({
    queryKey: ['meeting-minutes', id],
    queryFn: () => api.get(`/committee/meetings/${id}/minutes`).then(r => r.data.data),
    enabled: !!id,
  })

  const { data: members } = useQuery({
    queryKey: ['meeting-members', id],
    queryFn: () => api.get(`/committee/meetings/${id}/committee-members`).then(r => r.data.data),
    enabled: !!id,
  })

  const updateMeeting = useMutation({
    mutationFn: (data: any) => api.patch(`/committee/meetings/${id}`, data),
    onSuccess: () => {
      setStatusFilter('')
      queryClient.invalidateQueries({ queryKey: ['meeting', id] })
    },
    onError: (err: any) => toast.error(err.response?.data?.error || err.message),
  })

  const [statusFilter, setStatusFilter] = useState('')
  const [activeAgendaId, setActiveAgendaId] = useState<number | null>(null)

  const agendaForm = useForm<{ title: string; description?: string }>({
    resolver: zodResolver(meetingAgendaSchema),
    defaultValues: { title: '', description: '' },
  })
  const itemForm = useForm<{ title: string; application_id?: string }>({
    resolver: zodResolver(agendaItemSchema),
    defaultValues: { title: '', application_id: '' },
  })
  const attendForm = useForm<z.input<typeof attendanceSchema>>({
    resolver: zodResolver(attendanceSchema),
    defaultValues: { user_id: '', attendance_status: 'PRESENT', remarks: '' },
  })
  const minutesForm = useForm<{ minutes_text: string }>({
    resolver: zodResolver(minutesSchema),
    defaultValues: { minutes_text: '' },
  })
  const voteForm = useForm<{ application_id: string }>({
    resolver: zodResolver(votingSessionSchema),
    defaultValues: { application_id: '' },
  })

  const { data: votingSessions } = useQuery({
    queryKey: ['voting-sessions', id],
    queryFn: () => api.get(`/committee/voting/meeting/${id}`).then(r => r.data.data),
    enabled: !!id,
  })

  const [voteErrors, setVoteErrors] = useState<Record<string, string>>({})

  async function onAgenda(data: { title: string; description?: string }) {
    try {
      await api.post(`/committee/meetings/${id}/agenda`, data)
      agendaForm.reset()
      queryClient.invalidateQueries({ queryKey: ['meeting-agenda'] })
    } catch (err: any) {
      toast.error(err.response?.data?.error || t('meetings.saveFailed'))
    }
  }

  async function onItem(data: { title: string; application_id?: string }, agendaId: number) {
    try {
      await api.post(`/committee/meetings/${id}/agenda/${agendaId}/items`, { title: data.title, application_id: data.application_id || null })
      itemForm.reset()
      setActiveAgendaId(null)
      queryClient.invalidateQueries({ queryKey: ['meeting-agenda'] })
    } catch (err: any) {
      toast.error(err.response?.data?.error || t('meetings.saveFailed'))
    }
  }

  async function onAttendance(data: z.input<typeof attendanceSchema>) {
    try {
      await api.post(`/committee/meetings/${id}/attendance`, { user_id: parseInt(data.user_id), attendance_status: data.attendance_status, remarks: data.remarks })
      attendForm.reset()
      queryClient.invalidateQueries({ queryKey: ['meeting-attendance'] })
    } catch (err: any) {
      toast.error(err.response?.data?.error || t('meetings.saveFailed'))
    }
  }

  async function onMinutes(data: { minutes_text: string }) {
    try {
      await api.post(`/committee/meetings/${id}/minutes`, data)
      minutesForm.reset()
      queryClient.invalidateQueries({ queryKey: ['meeting-minutes'] })
    } catch (err: any) {
      toast.error(err.response?.data?.error || t('meetings.saveFailed'))
    }
  }

  async function approveMinutes(minutesId: number) {
    try {
      await api.patch(`/committee/meetings/${id}/minutes/${minutesId}/approve`)
      queryClient.invalidateQueries({ queryKey: ['meeting-minutes'] })
    } catch (err: any) {
      toast.error(err.response?.data?.error || t('meetings.saveFailed'))
    }
  }

  async function onNewVote(data: { application_id: string }) {
    try {
      await api.post('/committee/voting/sessions', { application_id: parseInt(data.application_id), meeting_id: parseInt(id!), voting_type: 'MAJORITY' })
      voteForm.reset()
      queryClient.invalidateQueries({ queryKey: ['voting-sessions'] })
    } catch (err: any) {
      toast.error(err.response?.data?.error || t('meetings.saveFailed'))
    }
  }

  async function castVote(sessionId: number, voteValue: string) {
    try {
      await api.post(`/committee/voting/sessions/${sessionId}/vote`, { vote_value: voteValue })
      setVoteErrors((prev: Record<string, string>) => ({ ...prev, [sessionId]: '' }))
      queryClient.invalidateQueries({ queryKey: ['voting-sessions'] })
    } catch (err: any) {
      setVoteErrors((prev: Record<string, string>) => ({ ...prev, [sessionId]: err.response?.data?.error || t('meetings.voteFailed') }))
    }
  }

  async function closeSession(sessionId: number) {
    try {
      await api.patch(`/committee/voting/sessions/${sessionId}/close`)
      queryClient.invalidateQueries({ queryKey: ['voting-sessions'] })
    } catch (err: any) {
      toast.error(err.response?.data?.error || t('meetings.saveFailed'))
    }
  }

  if (isLoading) return <PageSkeleton />
  if (!meeting) return <p className="text-red-500">{t('meetings.notFound')}</p>

  return (
    <div>
      <button onClick={() => navigate('/committee/meetings')} className="flex items-center gap-1 text-sm text-slate-500 hover:text-slate-700 mb-4">
        <ArrowLeft className="w-4 h-4" /> {t('meetings.back')}
      </button>

      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold">{meeting.meeting_number}</h1>
        <div className="flex items-center gap-2">
          <StatusBadge status={meeting.meeting_status} />
          {canEdit && (
            <select value={statusFilter || meeting.meeting_status} onChange={e => { setStatusFilter(e.target.value); updateMeeting.mutate({ meeting_status: e.target.value }) }}
              className="text-sm border rounded p-1">
              <option value="SCHEDULED">{t('meetings.scheduledLabel')}</option>
              <option value="IN_PROGRESS">{t('meetings.inProgressLabel')}</option>
              <option value="COMPLETED">{t('meetings.completedLabel')}</option>
              <option value="CANCELLED">{t('meetings.cancelledLabel')}</option>
            </select>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
        <div className="bg-white rounded-lg shadow p-4 flex items-center gap-3">
          <div className="bg-slate-100 p-2 rounded"><CalendarDays className="w-5 h-5 text-slate-600" /></div>
          <div><p className="text-xs text-slate-500">{t('meetings.date')}</p><p className="text-sm font-medium">{new Date(meeting.meeting_date).toLocaleString()}</p></div>
        </div>
        <div className="bg-white rounded-lg shadow p-4 flex items-center gap-3">
          <div className="bg-slate-100 p-2 rounded"><FileText className="w-5 h-5 text-slate-600" /></div>
          <div><p className="text-xs text-slate-500">{t('meetings.committee')}</p><p className="text-sm font-medium">{meeting.committee_name || '\u2014'}</p></div>
        </div>
        <div className="bg-white rounded-lg shadow p-4 flex items-center gap-3">
          <div className="bg-slate-100 p-2 rounded"><UserCheck className="w-5 h-5 text-slate-600" /></div>
          <div><p className="text-xs text-slate-500">{t('meetings.location')}</p><p className="text-sm font-medium">{meeting.location || '\u2014'}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <Card>
            <CardHeader><CardTitle className="text-sm flex items-center gap-2"><FileText className="w-4 h-4" /> {t('meetings.agenda')}</CardTitle></CardHeader>
            <CardContent>
              {agenda && agenda.length > 0 ? agenda.map((a: any) => (
                <div key={a.id} className="mb-4 pb-3 border-b last:border-0">
                  <p className="font-medium text-sm">{a.title}</p>
                  {a.description && <p className="text-xs text-slate-500">{a.description}</p>}
                  {a.items && a.items.length > 0 && (
                    <div className="ms-4 mt-2 space-y-1">
                      {a.items.map((item: any) => (
                        <div key={item.id} className="flex items-center gap-2 text-xs">
                          <span className="text-slate-400">#{item.item_order}</span>
                          <span className="font-medium">{item.title}</span>
                          {item.app_number && <span className="text-blue-600">({item.app_number})</span>}
                        </div>
                      ))}
                    </div>
                  )}
                  {canEdit && (
                    <div className="mt-2">
                      {activeAgendaId === a.id ? (
                        <form onSubmit={itemForm.handleSubmit((data) => onItem(data, a.id))} className="flex gap-2 items-center">
                          <Input size={20} placeholder={t('meetings.itemTitle')} {...itemForm.register('title')} className="text-xs" />
                          <Input size={10} placeholder={t('meetings.appId')} {...itemForm.register('application_id')} className="text-xs w-20" />
                          <Button type="submit" size="sm">{t('common.add')}</Button>
                          <button type="button" className="text-xs text-slate-400" onClick={() => { setActiveAgendaId(null); itemForm.reset() }}>{t('common.cancel')}</button>
                        </form>
                      ) : (
                        <Button size="sm" variant="outline" className="text-xs" onClick={() => setActiveAgendaId(a.id)}>{t('meetings.addItem')}</Button>
                      )}
                    </div>
                  )}
                </div>
              )) : <p className="text-sm text-slate-400">{t('meetings.noAgendaItems')}</p>}
              {canEdit && (
                <form onSubmit={agendaForm.handleSubmit(onAgenda)} className="mt-3 pt-3 border-t space-y-2">
                  <p className="text-xs font-medium text-slate-500">{t('meetings.addAgenda')}</p>
                  <Input placeholder={t('meetings.titlePlaceholder')} {...agendaForm.register('title')} className="text-sm" />
                  {agendaForm.formState.errors.title && <p className="text-red-500 text-xs">{agendaForm.formState.errors.title.message}</p>}
                  <Input placeholder={t('meetings.descriptionOptional')} {...agendaForm.register('description')} className="text-sm" />
                  <Button type="submit" size="sm">{t('meetings.addAgenda')}</Button>
                </form>
              )}
            </CardContent>
          </Card>
        </div>

        <div className="space-y-6">
          <Card>
            <CardHeader><CardTitle className="text-sm flex items-center gap-2"><UserCheck className="w-4 h-4" /> {t('meetings.attendance')}</CardTitle></CardHeader>
            <CardContent>
              {attendance && attendance.length > 0 ? (
                <div className="space-y-2">
                  {attendance.map((a: any) => (
                    <div key={a.id} className="flex items-center justify-between text-sm border-b pb-1 last:border-0">
                      <span className="font-medium">{a.display_name || a.username}</span>
                      <StatusBadge status={a.attendance_status} />
                    </div>
                  ))}
                </div>
              ) : <p className="text-sm text-slate-400">{t('meetings.noAttendance')}</p>}
              {canEdit && members && (
                <form onSubmit={attendForm.handleSubmit(onAttendance)} className="mt-3 pt-3 border-t space-y-2">
                  <p className="text-xs font-medium text-slate-500">{t('meetings.markAttendance')}</p>
                  <select {...attendForm.register('user_id')} className="w-full p-2 border rounded text-sm">
                    <option value="">{t('meetings.selectMember')}</option>
                    {members.map((m: any) => <option key={m.id} value={m.user_id}>{m.display_name || m.username}</option>)}
                  </select>
                  {attendForm.formState.errors.user_id && <p className="text-red-500 text-xs">{attendForm.formState.errors.user_id.message}</p>}
                  <select {...attendForm.register('attendance_status')} className="w-full p-2 border rounded text-sm">
                    <option value="PRESENT">{t('meetings.present')}</option>
                    <option value="ABSENT">{t('meetings.absent')}</option>
                    <option value="EXCUSED">{t('meetings.excused')}</option>
                    <option value="LATE">{t('meetings.late')}</option>
                  </select>
                  <Input placeholder={t('meetings.remarks')} {...attendForm.register('remarks')} className="text-sm" />
                  <Button type="submit" size="sm" className="w-full">{t('meetings.record')}</Button>
                </form>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader><CardTitle className="text-sm flex items-center gap-2"><MessageSquare className="w-4 h-4" /> {t('meetings.minutes')}</CardTitle></CardHeader>
            <CardContent>
              {minutes && minutes.length > 0 ? minutes.map((m: any) => (
                <div key={m.id} className="text-sm border-b pb-2 mb-2 last:border-0">
                  <p className="text-xs text-slate-600 whitespace-pre-wrap">{m.minutes_text}</p>
                  {m.created_by_username && <p className="text-xs text-slate-400 mt-1">{t('meetings.by', { name: m.created_by_username })}</p>}
                  <div className="flex items-center gap-2 mt-1">
                    <StatusBadge status={m.approved_by ? 'APPROVED' : 'DRAFT'} />
                    {m.approved_by_username && <span className="text-xs text-slate-400">{t('meetings.approvedBy', { name: m.approved_by_username })}</span>}
                    {m.signatures && m.signatures.length > 0 && (
                      <span className="text-xs text-green-600 font-medium">{t('meetings.signatures', { count: m.signatures.length })}</span>
                    )}
                  </div>
                  {m.signatures && m.signatures.length > 0 && (
                    <div className="mt-1 flex flex-wrap gap-2">
                      {m.signatures.map((s: any) => (
                        <span key={s.id} className="text-xs bg-green-50 text-green-700 px-1.5 py-0.5 rounded flex items-center gap-1">
                          {'\u270D'} {s.signer_name}
                        </span>
                      ))}
                    </div>
                  )}
                  <div className="flex gap-2 mt-1">
                    {canEdit && !m.approved_by && (
                      <button className="text-xs text-blue-600 hover:underline" onClick={() => approveMinutes(m.id)}>{t('meetings.voteApprove')}</button>
                    )}
                    {canEdit && m.signatures && !m.signatures.find((s: any) => s.signer_id === user?.id) && (
                      <button className="text-xs text-green-600 hover:underline" onClick={() => approveMinutes(m.id)}>{t('signatures.sign')}</button>
                    )}
                  </div>
                </div>
              )) : <p className="text-sm text-slate-400">{t('meetings.noMinutes')}</p>}
              {canEdit && (
                <form onSubmit={minutesForm.handleSubmit(onMinutes)} className="mt-3 pt-3 border-t space-y-2">
                  <p className="text-xs font-medium text-slate-500">{t('meetings.addMinutes')}</p>
                  <textarea {...minutesForm.register('minutes_text')} className="w-full p-2 border rounded text-sm" rows={4} />
                  {minutesForm.formState.errors.minutes_text && <p className="text-red-500 text-xs">{minutesForm.formState.errors.minutes_text.message}</p>}
                  <Button type="submit" size="sm" className="w-full">{t('meetings.addMinutes')}</Button>
                </form>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader><CardTitle className="text-sm flex items-center gap-2"><Vote className="w-4 h-4" /> {t('meetings.voting')}</CardTitle></CardHeader>
            <CardContent>
              {votingSessions && votingSessions.length > 0 ? votingSessions.map((s: any) => (
                <div key={s.id} className="text-sm border-b pb-3 mb-3 last:border-0">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="font-medium">{s.project_title || s.application_number}</p>
                      <StatusBadge status={s.status_code} />
                    </div>
                    {canEdit && s.status_code === 'OPEN' && (
                      <Button size="sm" variant="outline" className="text-xs" onClick={() => closeSession(s.id)}>{t('meetings.closeVoting')}</Button>
                    )}
                  </div>
                  {s.votes && s.votes.length > 0 && (
                    <div className="mt-2 space-y-1">
                      {s.votes.map((v: any) => (
                        <div key={v.id} className="flex items-center justify-between text-xs">
                          <span>{v.voter_name}</span>
                          <StatusBadge status={v.vote_value} />
                        </div>
                      ))}
                    </div>
                  )}
                  {s.status_code === 'OPEN' && !s.votes?.find((v: any) => v.voter_id === user?.id) && (
                    <div className="mt-2 flex gap-1">
                      <Button size="sm" variant="outline" className="text-xs text-green-600" onClick={() => castVote(s.id, 'APPROVE')}>{t('meetings.voteApprove')}</Button>
                      <Button size="sm" variant="outline" className="text-xs text-red-600" onClick={() => castVote(s.id, 'REJECT')}>{t('meetings.voteReject')}</Button>
                      <Button size="sm" variant="outline" className="text-xs text-slate-500" onClick={() => castVote(s.id, 'ABSTAIN')}>{t('meetings.voteAbstain')}</Button>
                    </div>
                  )}
                  {voteErrors[s.id] && <p className="text-red-500 text-xs mt-1">{voteErrors[s.id]}</p>}
                </div>
              )) : <p className="text-sm text-slate-400">{t('meetings.noVotingSessions')}</p>}
              {canEdit && (
                <form onSubmit={voteForm.handleSubmit(onNewVote)} className="mt-3 pt-3 border-t space-y-2">
                  <p className="text-xs font-medium text-slate-500">{t('meetings.newVotingSession')}</p>
                  <Input placeholder={t('meetings.applicationId')} {...voteForm.register('application_id')} className="text-sm" />
                  {voteForm.formState.errors.application_id && <p className="text-red-500 text-xs">{voteForm.formState.errors.application_id.message}</p>}
                  <Button type="submit" size="sm" className="w-full">{t('meetings.startVote')}</Button>
                </form>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  )
}

import { useQuery } from '@tanstack/react-query'
import { useNavigate } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import api from '../../api/client'
import DataTable from '../../components/DataTable'
import { CalendarDays } from 'lucide-react'

export default function CommitteeMeetings() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { data: committees } = useQuery({
    queryKey: ['committees'],
    queryFn: () => api.get('/committee/committees').then((r) => r.data.data),
  })

  const { data: meetings, isLoading } = useQuery({
    queryKey: ['committee-meetings'],
    queryFn: async () => {
      if (!committees || committees.length === 0) return []
      const results = await Promise.all(
        committees.map((c: any) =>
          api.get(`/committee/meetings/committee/${c.id}`).then((r) => r.data.data || [])
        )
      )
      return results.flat()
    },
    enabled: !!committees && committees.length > 0,
  })

  return (
    <div>
      <div className="flex items-center gap-3 mb-6">
        <CalendarDays className="w-6 h-6 text-blue-600" />
        <h1 className="text-2xl font-bold">{t('meetings.title')}</h1>
      </div>

        <DataTable
          loading={isLoading}
          columns={[
            { key: 'meeting_number', label: t('meetings.number'), sortable: true, render: (r) => <a href="#" onClick={(e) => { e.preventDefault(); navigate(`/committee/meetings/${r.id}`) }} className="text-blue-600 hover:underline">{r.meeting_number}</a> },
            { key: 'meeting_date', label: t('meetings.date'), sortable: true, render: (i) => new Date(i.meeting_date).toLocaleDateString() },
            { key: 'location', label: t('meetings.location'), sortable: true },
            { key: 'meeting_status', label: t('meetings.status'), sortable: true },
          ]}
          data={meetings || []}
          emptyMessage={t('meetings.noMeetings')}
        />
    </div>
  )
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useState, useRef } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { toast } from 'sonner'
import api from '../../api/client'
import DataTable from '../../components/DataTable'
import ConfirmDialog from '../../components/ConfirmDialog'
import { FileUp, Trash2 } from 'lucide-react'
import { Button } from '../../components/ui/button'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from '../../components/ui/dialog'
import { Input } from '../../components/ui/input'
import { Label } from '../../components/ui/label'
import { documentUploadSchema } from '../../lib/schemas'
import { useTranslation } from 'react-i18next'

type UploadFormData = { document_type_id?: string; entity_type?: string; entity_id?: string; document_title?: string }

export default function DocumentsPage() {
  const { t } = useTranslation()
  const queryClient = useQueryClient()
  const fileRef = useRef<HTMLInputElement>(null)
  const [open, setOpen] = useState(false)
  const [file, setFile] = useState<File | null>(null)

  const { register, handleSubmit, reset: resetForm } = useForm<UploadFormData>({
    resolver: zodResolver(documentUploadSchema),
  })

  const { data: documents, isLoading } = useQuery({
    queryKey: ['documents'],
    queryFn: () => api.get('/documents').then((r) => r.data.data),
  })

  const { data: types } = useQuery({
    queryKey: ['document-types'],
    queryFn: () => api.get('/documents/types').then((r) => r.data.data),
  })

  const uploadMutation = useMutation({
    mutationFn: (formData: FormData) => api.post('/documents', formData, { headers: { 'Content-Type': 'multipart/form-data' } }),
    onSuccess: () => { toast.success(t('documents.uploaded')); queryClient.invalidateQueries({ queryKey: ['documents'] }); setOpen(false); resetForm() },
    onError: (err: any) => toast.error(err.response?.data?.error || t('documents.uploadFailed')),
  })

  const [deleteTarget, setDeleteTarget] = useState<number | null>(null)
  const deleteMutation = useMutation({
    mutationFn: (id: number) => api.delete(`/documents/${id}`),
    onSuccess: () => { toast.success(t('documents.deleted')); queryClient.invalidateQueries({ queryKey: ['documents'] }); setDeleteTarget(null) },
  })

  function resetAll() {
    resetForm()
    setFile(null)
  }

  function onUpload(data: UploadFormData) {
    if (!file) { toast.error(t('documents.selectFile')); return }
    const fd = new FormData()
    fd.append('file', file)
    if (data.document_title) fd.append('document_title', data.document_title)
    if (data.document_type_id) fd.append('document_type_id', data.document_type_id)
    if (data.entity_type) fd.append('entity_type', data.entity_type)
    if (data.entity_id) fd.append('entity_id', data.entity_id)
    uploadMutation.mutate(fd)
  }

  function formatSize(bytes: number) {
    if (!bytes) return '—'
    if (bytes < 1024) return `${bytes} B`
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold">{t('documents.title')}</h1>
        <Dialog open={open} onOpenChange={(o) => { setOpen(o); if (!o) resetAll() }}>
          <DialogTrigger asChild><Button><FileUp className="w-4 h-4 mr-1" /> {t('documents.upload')}</Button></DialogTrigger>
          <form onSubmit={handleSubmit(onUpload)}>
          <DialogContent>
            <DialogHeader><DialogTitle>{t('documents.uploadTitle')}</DialogTitle></DialogHeader>
            <div className="space-y-4">
              <div><Label>{t('documents.file')}</Label><input type="file" ref={fileRef} onChange={(e) => setFile(e.target.files?.[0] || null)} className="w-full text-sm" /></div>
              <div><Label>{t('documents.titleLabel')}</Label><Input {...register('document_title')} placeholder={t('documents.titlePlaceholder')} /></div>
              <div><Label>{t('documents.type')}</Label>
                <select {...register('document_type_id')} className="w-full p-2 border rounded text-sm">
                  <option value="">{t('documents.selectType')}</option>
                  {(types || []).map((t: any) => <option key={t.id} value={t.id}>{t.type_name_ar || t.type_code}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div><Label>{t('documents.entityType')}</Label>
                  <select {...register('entity_type')} className="w-full p-2 border rounded text-sm">
                    <option value="">{t('documents.none')}</option>
                    <option value="Application">{t('documents.application')}</option>
                    <option value="Project">{t('documents.project')}</option>
                  </select>
                </div>
                <div><Label>{t('documents.entityId')}</Label><Input type="number" {...register('entity_id')} /></div>
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" type="button" onClick={() => setOpen(false)}>{t('common.cancel')}</Button>
              <Button type="submit" disabled={uploadMutation.isPending}>{uploadMutation.isPending ? t('common.uploading') : t('common.upload')}</Button>
            </DialogFooter>
          </DialogContent>
          </form>
        </Dialog>
      </div>

        <DataTable
          searchable
          loading={isLoading}
          columns={[
            { key: 'document_title', label: t('documents.titleLabel'), sortable: true },
            { key: 'type_name_ar', label: t('documents.type'), sortable: true },
            { key: 'entity_type', label: t('documents.entity'), render: (d: any) => d.entity_type ? `${d.entity_type} #${d.entity_id}` : '—' },
            { key: 'file_name', label: t('documents.fileName'), sortable: true },
            { key: 'file_size_bytes', label: t('documents.size'), sortable: true, render: (d: any) => formatSize(d.file_size_bytes) },
            { key: 'uploaded_by_username', label: t('documents.uploadedBy'), sortable: true },
            { key: 'uploaded_at', label: t('documents.date'), sortable: true, render: (d: any) => new Date(d.uploaded_at).toLocaleDateString() },
            { key: 'actions', label: '', render: (d: any) => (
              <button onClick={() => setDeleteTarget(d.id)} className="text-red-500 hover:text-red-700">
                <Trash2 className="w-4 h-4" />
              </button>
            )},
          ]}
          data={documents || []}
          emptyMessage={t('documents.empty')}
        />

      <ConfirmDialog
        open={deleteTarget !== null}
        onOpenChange={(o) => { if (!o) setDeleteTarget(null) }}
        title={t('documents.deleteTitle')}
        description={t('documents.deleteConfirm')}
        onConfirm={() => deleteTarget && deleteMutation.mutate(deleteTarget)}
        loading={deleteMutation.isPending}
      />
    </div>
  )
}

import { useState } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import api from '../../api/client'
import { Card, CardContent } from '../../components/ui/card'
import { Button } from '../../components/ui/button'
import { PenSquare, FileSignature, CheckCircle, FileText } from 'lucide-react'
import { useTranslation } from 'react-i18next'

export default function ESignaturesPage() {
  const { t } = useTranslation()
  const queryClient = useQueryClient()
  const [signingId, setSigningId] = useState<number | null>(null)
  const [signError, setSignError] = useState('')

  const { data: documents } = useQuery({
    queryKey: ['documents'],
    queryFn: () => api.get('/documents').then(r => r.data.data || []),
  })

  const signMutation = useMutation({
    mutationFn: (id: number) => api.post(`/documents/${id}/sign`),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ['documents'] }); setSigningId(null); setSignError('') },
    onError: (err: any) => setSignError(err.response?.data?.error || t('signatures.failed')),
  })

  return (
    <div>
      <div className="flex items-center gap-3 mb-6">
        <PenSquare className="w-6 h-6 text-blue-600" />
        <h1 className="text-2xl font-bold">{t('signatures.title')}</h1>
      </div>

      {signError && <p className="text-red-500 text-sm mb-4">{signError}</p>}

      <div className="space-y-3">
        {documents && documents.length > 0 ? documents.map((doc: any) => (
          <DocumentSignCard key={doc.id} doc={doc} onSign={(id) => signMutation.mutate(id)} signingId={signingId} />
        )) : (
          <Card><CardContent className="p-12 text-center text-slate-400"><FileSignature className="w-12 h-12 mx-auto mb-3 opacity-30" /><p>{t('signatures.empty')}</p></CardContent></Card>
        )}
      </div>
    </div>
  )
}

function DocumentSignCard({ doc, onSign, signingId }: { doc: any; onSign: (id: number) => void; signingId: number | null }) {
  const { t } = useTranslation()
  const { data: signatures } = useQuery({
    queryKey: ['doc-signatures', doc.id],
    queryFn: () => api.get(`/documents/${doc.id}/signatures`).then(r => r.data.data),
  })

  const sigCount = signatures?.length || 0

  return (
    <Card>
      <CardContent className="p-4">
        <div className="flex items-start justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-100 p-2 rounded">
              <FileText className="w-5 h-5 text-blue-600" />
            </div>
            <div>
              <p className="font-medium text-sm">{doc.document_title}</p>
              <p className="text-xs text-slate-400">{doc.type_name_ar || doc.file_name} • {t('signatures.count', { count: sigCount })}</p>
            </div>
          </div>
          <Button size="sm" onClick={() => onSign(doc.id)} disabled={signingId === doc.id}>
            {signingId === doc.id ? t('signatures.signing') : <><PenSquare className="w-3 h-3 mr-1" /> {t('signatures.sign')}</>}
          </Button>
        </div>

        {signatures && signatures.length > 0 && (
          <div className="mt-3 pt-3 border-t space-y-1">
            {signatures.map((s: any) => (
              <div key={s.id} className="flex items-center gap-2 text-xs text-slate-500">
                <CheckCircle className="w-3 h-3 text-green-500" />
                <span className="font-medium">{s.signer_name}</span>
                <span>• {new Date(s.signed_at).toLocaleString()}</span>
                <span className="text-slate-300">({s.signature_type})</span>
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  )
}

import { useForm } from 'react-hook-form'
