                { key: 'name_en', label: t('registry.nameEn') },
                { key: 'type', label: t('registry.type') },
                { key: 'city', label: t('registry.city') },
                { key: 'is_accredited', label: t('registry.accredited'), render: (i: any) => i.is_accredited ? <StatusBadge status="APPROVED" /> : <StatusBadge status="DRAFT" /> },
              ]}
              data={institutions || []}
            />
          )}
          {tab === 'professions' && (
            <DataTable
              columns={[
                { key: 'code', label: t('registry.code') },
                { key: 'name_ar', label: t('registry.nameAr') },
                { key: 'name_en', label: t('registry.nameEn') },
                { key: 'category', label: t('registry.category') },
              ]}
              data={professions || []}
            />
          )}
          {tab === 'licenses' && (
            <DataTable
              columns={[
                { key: 'profession_name', label: t('registry.profession') },
                { key: 'user_name', label: t('registry.user') },
                { key: 'verification_status', label: t('registry.verification'), render: (l: any) => <StatusBadge status={l.verification_status} /> },
              ]}
              data={licenses || []}
            />
          )}
        </CardContent>
      </Card>
    </div>
  )
}

import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { useNavigate, useSearchParams, Link } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { toast } from 'sonner'
import api from '../api/client'
import { Button } from '../components/ui/button'
import { Input } from '../components/ui/input'
import { Card, CardContent, CardHeader, CardTitle } from '../components/ui/card'
import { resetPasswordSchema } from '../lib/schemas'
import { z } from 'zod'

type ResetFormData = z.input<typeof resetPasswordSchema>

export default function ResetPasswordPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const token = searchParams.get('token') || ''

  const { register, handleSubmit, formState: { errors, isSubmitting } } = useForm<ResetFormData>({
    resolver: zodResolver(resetPasswordSchema),
    defaultValues: { token, password: '', confirmPassword: '' },
  })

  async function onSubmit(data: ResetFormData) {
    try {
      await api.post('/security/auth/reset-password', {
        token: data.token,
        password: data.password,
      })
      toast.success(t('resetPassword.success'))
      navigate('/login')
    } catch (err: any) {
      toast.error(err.response?.data?.error || t('resetPassword.failed'))
    }
  }

  if (!token) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-muted px-4">
        <Card className="w-full max-w-sm">
          <CardContent className="text-center py-8">
            <p className="text-red-500 text-sm">{t('resetPassword.invalidToken')}</p>
            <Link to="/forgot-password" className="text-blue-600 hover:underline text-sm">{t('resetPassword.requestNew')}</Link>
          </CardContent>
        </Card>
      </div>
    )
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-muted px-4">
      <Card className="w-full max-w-sm">
        <CardHeader className="text-center">
          <CardTitle className="text-blue-700 text-xl">{t('resetPassword.title')}</CardTitle>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
            <Input type="hidden" {...register('token')} />
            <Input type="password" placeholder={t('resetPassword.newPassword')} {...register('password')} />
            {errors.password && <p className="text-red-500 text-xs">{errors.password.message}</p>}
            <Input type="password" placeholder={t('resetPassword.confirmPassword')} {...register('confirmPassword')} />
            {errors.confirmPassword && <p className="text-red-500 text-xs">{errors.confirmPassword.message}</p>}
            <Button type="submit" className="w-full" disabled={isSubmitting}>
              {isSubmitting ? t('common.saving') : t('resetPassword.submit')}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  )
}

import { useState } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'
import api from '../../api/client'
import ConfirmDialog from '../../components/ConfirmDialog'
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card'
import { Button } from '../../components/ui/button'
import { Input } from '../../components/ui/input'
import { Textarea } from '../../components/ui/textarea'
import { reviewFormSchema, addQuestionSchema } from '../../lib/schemas'
import { z } from 'zod'
import { ClipboardList, Plus, Trash2, ChevronDown, ChevronRight } from 'lucide-react'
import { PageSkeleton } from '../../components/LoadingSkeleton'
import { useTranslation } from 'react-i18next'

type FormFormData = z.input<typeof reviewFormSchema>
type QuestionFormData = z.input<typeof addQuestionSchema>

export default function ReviewFormsPage() {
  const { t } = useTranslation()
  const queryClient = useQueryClient()
  const [expandedForm, setExpandedForm] = useState<number | null>(null)
  const [showCreateForm, setShowCreateForm] = useState(false)
  const [addingQuestion, setAddingQuestion] = useState<number | null>(null)

  const formForm = useForm<FormFormData>({
    resolver: zodResolver(reviewFormSchema),
    defaultValues: { form_code: '', form_name: '', review_type: 'ETHICS' },
  })
  const questionForm = useForm<QuestionFormData>({
    resolver: zodResolver(addQuestionSchema),
    defaultValues: { question_code: '', question_text: '', question_type: 'TEXT', is_required: true, question_options: '' },
  })

  const { data: forms, isLoading } = useQuery({
    queryKey: ['review-forms'],
    queryFn: () => api.get('/committee/reviews/forms').then(r => r.data.data),
  })

  const { data: questions } = useQuery({
    queryKey: ['form-questions', expandedForm],
    queryFn: () => api.get(`/committee/reviews/forms/${expandedForm}/questions`).then(r => r.data.data),
    enabled: !!expandedForm,
  })

  const createFormMut = useMutation({
    mutationFn: (data: any) => api.post('/committee/reviews/forms', data),
    onSuccess: () => { toast.success(t('reviewForms.created')); queryClient.invalidateQueries({ queryKey: ['review-forms'] }); setShowCreateForm(false); formForm.reset() },
    onError: (err: any) => toast.error(err.response?.data?.error || t('reviewForms.createFailed')),
  })

  const addQuestionMut = useMutation({
    mutationFn: (data: any) => api.post(`/committee/reviews/forms/${expandedForm}/questions`, data),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ['form-questions'] }); setAddingQuestion(null); questionForm.reset() },
    onError: (err: any) => toast.error(err.response?.data?.error || t('reviewForms.addQuestionFailed')),
  })

  const [deleteTarget, setDeleteTarget] = useState<number | null>(null)
  const deleteQuestionMut = useMutation({
    mutationFn: (id: number) => api.delete(`/committee/reviews/forms/${expandedForm}/questions/${id}`),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ['form-questions'] }); setDeleteTarget(null) },
  })

  function onCreateForm(data: FormFormData) {
    createFormMut.mutate(data)
  }

  function onAddQuestion(data: QuestionFormData) {
    addQuestionMut.mutate(data)
  }

  if (isLoading) return <PageSkeleton />

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-3">
          <ClipboardList className="w-6 h-6 text-blue-600" />
          <h1 className="text-2xl font-bold">{t('reviewForms.title')}</h1>
        </div>
        <Button size="sm" onClick={() => setShowCreateForm(true)}><Plus className="w-3 h-3 mr-1" /> {t('reviewForms.new')}</Button>
      </div>

      {showCreateForm && (
        <Card className="mb-6">
          <CardHeader><CardTitle className="text-sm">{t('reviewForms.create')}</CardTitle></CardHeader>
          <CardContent>
            <form onSubmit={formForm.handleSubmit(onCreateForm)} className="space-y-3">
              <div className="grid grid-cols-3 gap-3">
                <div><Input placeholder={t('reviewForms.codePlaceholder')} {...formForm.register('form_code')} className="text-sm" />{formForm.formState.errors.form_code && <p className="text-red-500 text-xs">{formForm.formState.errors.form_code.message}</p>}</div>
                <div><Input placeholder={t('reviewForms.namePlaceholder')} {...formForm.register('form_name')} className="text-sm" />{formForm.formState.errors.form_name && <p className="text-red-500 text-xs">{formForm.formState.errors.form_name.message}</p>}</div>
                <select {...formForm.register('review_type')} className="p-2 border rounded text-sm">
                  <option value="ETHICS">{t('reviewForms.ethicsReview')}</option>
                  <option value="SCIENTIFIC">{t('reviewForms.scientificReview')}</option>
                </select>
              </div>
              <div className="flex gap-2">
                <Button size="sm" type="submit" disabled={createFormMut.isPending}>{t('common.create')}</Button>
                <Button size="sm" variant="outline" type="button" onClick={() => setShowCreateForm(false)}>{t('common.cancel')}</Button>
              </div>
            </form>
          </CardContent>
        </Card>
      )}

      <div className="space-y-3">
        {forms && forms.length > 0 ? forms.map((f: any) => (
          <Card key={f.id}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between cursor-pointer" onClick={() => setExpandedForm(expandedForm === f.id ? null : f.id)}>
                <div className="flex items-center gap-3">
                  {expandedForm === f.id ? <ChevronDown className="w-4 h-4 text-slate-400" /> : <ChevronRight className="w-4 h-4 text-slate-400" />}
                  <div>
                    <p className="font-medium text-sm">{f.form_name}</p>
                    <p className="text-xs text-slate-400">{f.form_code} • v{f.version_no} • {f.review_type} • {t('reviewForms.questions', { count: f.question_count })}</p>
                  </div>
                </div>
                <span className={`text-xs px-2 py-0.5 rounded ${f.is_active ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-500'}`}>
                  {f.is_active ? t('reviewForms.active') : t('reviewForms.inactive')}
                </span>
              </div>

              {expandedForm === f.id && (
                <div className="mt-4 pt-3 border-t">
                  {questions && questions.length > 0 ? (
                    <div className="space-y-2 mb-3">
                      {questions.map((q: any) => (
                        <div key={q.id} className="flex items-center justify-between text-sm border-b pb-1 last:border-0">
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-400 w-6">#{q.display_order}</span>
                            <span className="font-medium">{q.question_text}</span>
                            <span className="text-xs text-slate-400 bg-slate-100 px-1.5 py-0.5 rounded">{q.question_type}</span>
                            {q.is_required && <span className="text-xs text-red-500">*</span>}
                          </div>
                          <button onClick={() => setDeleteTarget(q.id)} className="text-slate-300 hover:text-red-500">
                            <Trash2 className="w-3.5 h-3.5" />
                          </button>
                        </div>
                      ))}
                    </div>
                  ) : <p className="text-sm text-slate-400 mb-3">{t('reviewForms.noQuestions')}</p>}

                  {addingQuestion === f.id ? (
                    <form onSubmit={questionForm.handleSubmit(onAddQuestion)} className="border-t pt-2 space-y-2">
                      <div className="flex gap-2 items-center">
                        <Input size={12} placeholder={t('reviewForms.questionCode')} {...questionForm.register('question_code')} className="text-xs w-24" />
                        <Input size={30} placeholder={t('reviewForms.questionText')} {...questionForm.register('question_text')} className="text-xs flex-1" />
                        <select {...questionForm.register('question_type')} className="p-1.5 border rounded text-xs">
                          <option value="TEXT">{t('reviewForms.text')}</option>
                          <option value="SCALE">{t('reviewForms.scale')}</option>
                          <option value="BOOLEAN">{t('reviewForms.yesNo')}</option>
                          <option value="CHOICE">{t('reviewForms.choice')}</option>
                        </select>
                        <label className="flex items-center gap-1 text-xs whitespace-nowrap"><input type="checkbox" {...questionForm.register('is_required')} /> {t('reviewForms.required')}</label>
                        <Button size="sm" type="submit" disabled={addQuestionMut.isPending}>{t('common.add')}</Button>
                        <button type="button" className="text-xs text-slate-400" onClick={() => setAddingQuestion(null)}>{t('common.cancel')}</button>
                      </div>
                      {questionForm.watch('question_type') === 'CHOICE' && (
                        <Textarea
                          placeholder={t('reviewForms.optionsPlaceholder')}
                          {...questionForm.register('question_options')}
                          className="text-xs"
                          rows={3}
                        />
                      )}
                    </form>
                  ) : (
                    <button className="text-xs text-blue-600 hover:underline mt-2 inline-block" onClick={() => { setAddingQuestion(f.id); questionForm.reset() }}>
                      {t('reviewForms.addQuestion')}
                    </button>
                  )}
                </div>
              )}
            </CardContent>
          </Card>
        )) : <p className="text-slate-400">{t('reviewForms.empty')}</p>}
      </div>

      <ConfirmDialog
        open={deleteTarget !== null}
        onOpenChange={(o) => { if (!o) setDeleteTarget(null) }}
        title={t('reviewForms.deleteQuestionTitle')}
        description={t('reviewForms.deleteQuestionConfirm')}
        onConfirm={() => deleteTarget && deleteQuestionMut.mutate(deleteTarget)}
        loading={deleteQuestionMut.isPending}
      />
    </div>
  )
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useState } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { useTranslation } from 'react-i18next'
import { toast } from 'sonner'
import api from '../../api/client'
import { Shield, Plus, Pencil } from 'lucide-react'
import { usePermission } from '../../hooks/usePermission'
import { z } from 'zod'
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter,
} from '../../components/ui/dialog'
import { Button } from '../../components/ui/button'

const roleCreateSchema = z.object({
  code: z.string({ message: 'Code is required' }).min(1).max(50),
  name_ar: z.string({ message: 'Arabic name is required' }).min(1).max(200),
  name_en: z.string().max(200).optional().default(''),
  description: z.string().max(500).optional().default(''),
})

type RoleCreateFormData = z.input<typeof roleCreateSchema>

interface Permission {
  id: number
  permission_code: string
  module_name: string
  action_name: string
  description: string
  granted?: boolean
}

interface Role {
  id: number
  code: string
  name_ar: string
  name_en: string
  description?: string
  is_active: boolean
  is_system_role: boolean
}

export default function RoleList() {
  const { t } = useTranslation()
  const queryClient = useQueryClient()
  const [selectedRole, setSelectedRole] = useState<Role | null>(null)
  const [permissions, setPermissions] = useState<Permission[]>([])
  const [error, setError] = useState('')
  const [saving, setSaving] = useState(false)
  const [showCreate, setShowCreate] = useState(false)
  const [editId, setEditId] = useState<number | null>(null)
  const canCreate = usePermission('role.create')
  const canUpdate = usePermission('role.update')

  const { register, handleSubmit, reset, formState: { errors } } = useForm<RoleCreateFormData>({
    resolver: zodResolver(roleCreateSchema),
    defaultValues: { code: '', name_ar: '', name_en: '', description: '' },
  })

  const editForm = useForm<any>({
    defaultValues: { name_ar: '', name_en: '', description: '', is_active: true },
  })

  const { data: roles, isLoading: rolesLoading } = useQuery({
    queryKey: ['roles'],
    queryFn: () => api.get('/security/roles').then((r) => r.data.data),
  })

  const createMutation = useMutation({
    mutationFn: (body: any) => api.post('/security/roles', body),
    onSuccess: () => { toast.success(t('roles.created')); queryClient.invalidateQueries({ queryKey: ['roles'] }); setShowCreate(false); reset() },
    onError: (err: any) => toast.error(err.response?.data?.error || t('roles.createFailed')),
  })

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: number; data: any }) => api.put(`/security/roles/${id}`, data),
    onSuccess: () => { toast.success(t('roles.updated')); queryClient.invalidateQueries({ queryKey: ['roles'] }); setEditId(null) },
    onError: (err: any) => toast.error(err.response?.data?.error || t('roles.updateFailed')),
  })

  function openPermissions(role: Role) {
    setEditId(null)
    setSelectedRole(role)
    setError('')
    api.get(`/security/permissions/role/${role.id}`).then((r) => {
      setPermissions(r.data.data)
    }).catch((err) => {
      setError(err.response?.data?.error || t('roles.loadPermsFailed'))
    })
  }

  function togglePermission(permId: number) {
    setPermissions((prev) =>
      prev.map((p) => (p.id === permId ? { ...p, granted: !p.granted } : p))
    )
  }

  function savePermissions() {
    if (!selectedRole) return
    setSaving(true)
    setError('')
    const permission_ids = permissions.filter((p) => p.granted).map((p) => p.id)
    api.put(`/security/permissions/role/${selectedRole.id}`, { permission_ids })
      .then(() => {
        queryClient.invalidateQueries({ queryKey: ['roles'] })
        setSelectedRole(null)
        setPermissions([])
      })
      .catch((err) => {
        setError(err.response?.data?.error || t('roles.savePermsFailed'))
      })
      .finally(() => setSaving(false))
  }

  function openEdit(role: Role) {
    setSelectedRole(null)
    setPermissions([])
    editForm.reset({
      name_ar: role.name_ar || '',
      name_en: role.name_en || '',
      description: role.description || '',
      is_active: role.is_active ?? true,
    })
    setEditId(role.id)
  }

  const modules = permissions.reduce<Record<string, Permission[]>>((acc, p) => {
    const m = p.module_name || 'other'
    if (!acc[m]) acc[m] = []
    acc[m].push(p)
    return acc
  }, {})

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold">{t('roles.title')}</h1>
        {canCreate && (
          <button onClick={() => setShowCreate(!showCreate)}
            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 text-sm">
            <Plus className="w-4 h-4" /> {t('roles.new')}
          </button>
        )}
      </div>

      {editId && (
        <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center" onClick={() => setEditId(null)}>
          <div className="bg-white rounded-lg p-6 max-w-lg w-full mx-4 shadow-xl" onClick={e => e.stopPropagation()}>
            <h2 className="font-semibold mb-4">{t('roles.edit')}</h2>
            <form onSubmit={editForm.handleSubmit((data) => updateMutation.mutate({ id: editId, data }))} className="space-y-3">
              <div className="grid grid-cols-2 gap-3">
                <input placeholder={t('roles.nameAr')} {...editForm.register('name_ar')} className="p-2 border rounded text-sm" />
                <input placeholder={t('roles.nameEn')} {...editForm.register('name_en')} className="p-2 border rounded text-sm" />
              </div>
              <input placeholder={t('roles.description')} {...editForm.register('description')} className="w-full p-2 border rounded text-sm" />
              <label className="flex items-center gap-2 text-sm">
                <input type="checkbox" {...editForm.register('is_active')} />
                {t('roles.active')}
              </label>
              <div className="flex gap-3">
                <button type="submit" disabled={updateMutation.isPending} className="bg-blue-600 text-white px-4 py-2 rounded text-sm disabled:opacity-50">
                  {updateMutation.isPending ? t('common.saving') : t('common.save')}
                </button>
                <button type="button" onClick={() => setEditId(null)} className="bg-slate-200 text-slate-700 px-4 py-2 rounded text-sm">{t('common.cancel')}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showCreate && (
        <div className="bg-white p-6 rounded-lg shadow mb-6 max-w-lg">
          <h2 className="font-semibold mb-4">{t('roles.create')}</h2>
          <form onSubmit={handleSubmit((data) => createMutation.mutate(data))} className="space-y-3">
            <div className="grid grid-cols-2 gap-3">
              <div><input placeholder={t('roles.code')} {...register('code')} className="w-full p-2 border rounded text-sm" />{errors.code && <p className="text-red-500 text-xs">{errors.code.message}</p>}</div>
              <div><input placeholder={t('roles.nameAr')} {...register('name_ar')} className="w-full p-2 border rounded text-sm" />{errors.name_ar && <p className="text-red-500 text-xs">{errors.name_ar.message}</p>}</div>
            </div>
            <input placeholder={t('roles.nameEn')} {...register('name_en')} className="w-full p-2 border rounded text-sm" />
            <input placeholder={t('roles.description')} {...register('description')} className="w-full p-2 border rounded text-sm" />
            <div className="flex gap-3">
              <button type="submit" disabled={createMutation.isPending} className="bg-blue-600 text-white px-4 py-2 rounded text-sm disabled:opacity-50">
                {createMutation.isPending ? t('common.creating') : t('common.create')}
              </button>
              <button type="button" onClick={() => setShowCreate(false)} className="bg-slate-200 text-slate-700 px-4 py-2 rounded text-sm">{t('common.cancel')}</button>
            </div>
          </form>
        </div>
      )}

      {rolesLoading ? (
        <p className="text-slate-400">{t('common.loading')}</p>
      ) : (
        <div className="rounded-lg border overflow-hidden">
          <table className="w-full text-sm">
            <thead className="bg-slate-50">
              <tr>
                <th className="text-start px-4 py-3 font-medium">{t('roles.code')}</th>
                <th className="text-start px-4 py-3 font-medium">{t('roles.nameAr')}</th>
                <th className="text-start px-4 py-3 font-medium">{t('roles.active')}</th>
                <th className="text-start px-4 py-3 font-medium">{t('roles.permissions')}</th>
                {canUpdate && <th className="px-4 py-3 font-medium"></th>}
              </tr>
            </thead>
            <tbody>
              {(roles || []).map((role: Role) => (
                <tr key={role.id} className="border-t hover:bg-slate-50">
                  <td className="px-4 py-3 font-mono text-xs">{role.code}</td>
                  <td className="px-4 py-3">{role.name_ar}</td>
                  <td className="px-4 py-3">{role.is_active ? <span className="text-green-600">{'\u2713'}</span> : '\u2014'}</td>
                  <td className="px-4 py-3">
                    <Button variant="outline" size="sm" onClick={() => openPermissions(role)}>
                      <Shield className="w-3 h-3 me-1" /> {t('roles.manage')}
                    </Button>
                  </td>
                  {canUpdate && (
                    <td className="px-4 py-3">
                      <button onClick={() => openEdit(role)} className="text-slate-400 hover:text-blue-600"><Pencil className="w-4 h-4" /></button>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <Dialog open={!!selectedRole} onOpenChange={(o) => { if (!o) { setSelectedRole(null); setPermissions([]) } }}>
        <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{t('roles.permissionsTitle', { name: selectedRole?.name_ar || selectedRole?.code })}</DialogTitle>
          </DialogHeader>

          {error && <p className="text-red-500 text-sm mb-2">{error}</p>}

          {permissions.length === 0 && !error ? (
            <p className="text-slate-400 text-sm py-4">{t('roles.loadingPerms')}</p>
          ) : (
            <div className="space-y-4">
              {Object.entries(modules).map(([module, perms]) => (
                <div key={module}>
                  <h3 className="font-semibold text-sm capitalize mb-2 text-slate-700 border-b pb-1">
                    {module}
                  </h3>
                  <div className="grid grid-cols-1 gap-1.5">
                    {perms.map((perm) => (
                      <label key={perm.id} className="flex items-center gap-2 text-sm px-2 py-1 rounded hover:bg-slate-50 cursor-pointer">
                        <input type="checkbox" checked={perm.granted || false} onChange={() => togglePermission(perm.id)} className="rounded border-slate-300" />
                        <span className="font-mono text-xs text-slate-500 min-w-[140px]">{perm.permission_code}</span>
                        <span className="text-slate-700">{perm.description}</span>
                      </label>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}

          <DialogFooter>
            <Button variant="outline" onClick={() => { setSelectedRole(null); setPermissions([]) }}>{t('common.cancel')}</Button>
            <Button onClick={savePermissions} disabled={saving || permissions.length === 0}>
              {saving ? t('common.saving') : t('common.save')}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useState } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { toast } from 'sonner'
import api from '../../api/client'
import DataTable from '../../components/DataTable'
import ConfirmDialog from '../../components/ConfirmDialog'
import { Button } from '../../components/ui/button'
import { Card, CardContent } from '../../components/ui/card'
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter,
} from '../../components/ui/dialog'
import { Input } from '../../components/ui/input'
import { Label } from '../../components/ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../../components/ui/select'
import { savedSearchSchema } from '../../lib/schemas'
import { Trash2 } from 'lucide-react'
import { useTranslation } from 'react-i18next'

type SearchFormData = { name: string; search_type: string; criteria?: string; is_shared?: boolean }

export default function SavedSearches() {
  const { t } = useTranslation()
  const queryClient = useQueryClient()
  const [open, setOpen] = useState(false)
  const { register, handleSubmit, setValue, watch, reset, formState: { errors } } = useForm<SearchFormData>({
    resolver: zodResolver(savedSearchSchema),
    defaultValues: { name: '', search_type: 'applications', criteria: '{}', is_shared: false },
  })
  const entityType = watch('search_type')
  const isShared = watch('is_shared')

  const { data: searches, isLoading } = useQuery({
    queryKey: ['saved-searches'],
    queryFn: () => api.get('/system/saved-searches').then(r => r.data.data),
  })

  const createMutation = useMutation({
    mutationFn: (body: any) => api.post('/system/saved-searches', body),
    onSuccess: () => { toast.success(t('savedSearches.saved')); queryClient.invalidateQueries({ queryKey: ['saved-searches'] }); setOpen(false); reset() },
    onError: (err: any) => toast.error(err.response?.data?.error || t('savedSearches.saveFailed')),
  })

  const [deleteTarget, setDeleteTarget] = useState<number | null>(null)
  const deleteMutation = useMutation({
    mutationFn: (id: number) => api.delete(`/system/saved-searches/${id}`),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ['saved-searches'] }); setDeleteTarget(null) },
  })

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold">{t('savedSearches.title')}</h1>
        <Dialog open={open} onOpenChange={setOpen}>
          <DialogTrigger asChild><Button>{t('savedSearches.new')}</Button></DialogTrigger>
          <DialogContent>
            <form onSubmit={handleSubmit((data) => createMutation.mutate(data))}>
            <DialogHeader><DialogTitle>{t('savedSearches.save')}</DialogTitle></DialogHeader>
            <div className="space-y-4">
              <div><Label>{t('savedSearches.name')}</Label><Input {...register('name')} />{errors.name && <p className="text-red-500 text-xs">{errors.name.message}</p>}</div>
              <div><Label>{t('savedSearches.entityType')}</Label>
                <Select value={entityType} onValueChange={v => setValue('search_type', v, { shouldDirty: true })}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="applications">{t('savedSearches.applications')}</SelectItem>
                    <SelectItem value="projects">{t('savedSearches.projects')}</SelectItem>
                    <SelectItem value="users">{t('savedSearches.users')}</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div><Label>{t('savedSearches.criteria')}</Label><Input {...register('criteria')} /></div>
              <label className="flex items-center gap-2">
                <input type="checkbox" checked={!!isShared} onChange={e => setValue('is_shared', e.target.checked, { shouldDirty: true })} />
                <span className="text-sm">{t('savedSearches.share')}</span>
              </label>
            </div>
            <DialogFooter>
              <Button variant="outline" type="button" onClick={() => setOpen(false)}>{t('common.cancel')}</Button>
              <Button type="submit" disabled={createMutation.isPending}>{t('common.save')}</Button>
            </DialogFooter>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      <Card>
        <CardContent className="p-0">
          {isLoading ? (
            <div className="p-8 text-center text-muted-foreground">{t('common.loading')}</div>
          ) : (
            <DataTable
              columns={[
                { key: 'name', label: t('savedSearches.name') },
                { key: 'search_type', label: t('savedSearches.type') },
                { key: 'is_shared', label: t('savedSearches.shared'), render: (s: any) => s.is_shared ? t('common.yes') : t('common.no') },
                { key: 'created_at', label: t('savedSearches.created'), render: (s: any) => s.created_at ? new Date(s.created_at).toLocaleDateString() : '-' },
                { key: 'actions', label: '', render: (s: any) => (
                  <Button variant="ghost" size="icon" onClick={() => setDeleteTarget(s.id)}>
                    <Trash2 className="w-4 h-4 text-destructive" />
                  </Button>
                )},
              ]}
              data={searches || []}
            />
          )}
        </CardContent>
      </Card>

      <ConfirmDialog
        open={deleteTarget !== null}
        onOpenChange={(o) => { if (!o) setDeleteTarget(null) }}
        title={t('savedSearches.deleteTitle')}
        description={t('savedSearches.deleteConfirm')}
        onConfirm={() => deleteTarget && deleteMutation.mutate(deleteTarget)}
        loading={deleteMutation.isPending}
      />
    </div>
  )
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useState, useEffect } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { useTranslation } from 'react-i18next'
import { toast } from 'sonner'
import api from '../../api/client'
import DataTable from '../../components/DataTable'
import { Plus, Pencil, ChevronLeft, ChevronRight } from 'lucide-react'
import { usePermission } from '../../hooks/usePermission'
import { createUserSchema } from '../../lib/schemas'
import { z } from 'zod'

type UserFormData = z.input<typeof createUserSchema>

export default function UserList() {
  const { t } = useTranslation()
  const queryClient = useQueryClient()
  const [showCreate, setShowCreate] = useState(false)
  const [editUserId, setEditUserId] = useState<number | null>(null)
  const [searchQuery, setSearchQuery] = useState('')
  const [institutionFilter, setInstitutionFilter] = useState('')
  const [roleFilter, setRoleFilter] = useState('')
  const [statusFilter, setStatusFilter] = useState('')
  const [page, setPage] = useState(1)
  const [sortKey, setSortKey] = useState<string | null>(null)
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc')
  const canCreate = usePermission('user.create')
  const canUpdate = usePermission('user.update')

  const { register, handleSubmit, setValue, watch, reset, formState: { errors, isSubmitting } } = useForm<UserFormData>({
    resolver: zodResolver(createUserSchema),
    defaultValues: { username: '', email: '', password: '', role_codes: [], first_name_ar: '', last_name_ar: '', first_name_en: '', last_name_en: '', mobile: '', institution_id: '', department_id: '' },
  })
  const roleCodes = watch('role_codes')

  const editForm = useForm<any>({
    defaultValues: { email: '', first_name_ar: '', last_name_ar: '', first_name_en: '', last_name_en: '', mobile: '', institution_id: '', department_id: '', status: 'ACTIVE', role_codes: [] },
  })
  const editRoleCodes = editForm.watch('role_codes')

  const { data, isLoading } = useQuery({
    queryKey: ['users', searchQuery, institutionFilter, roleFilter, statusFilter, page, sortKey, sortDir],
    queryFn: () => api.get('/security/users', { params: { search: searchQuery || undefined, institution_id: institutionFilter || undefined, role_code: roleFilter || undefined, status: statusFilter || undefined, page, limit: 20, sort_by: sortKey || undefined, sort_order: sortKey ? sortDir : undefined } }).then((r) => r.data),
    placeholderData: (prev) => prev,
  })

  const users = data?.data || []
  const pagination = data?.pagination || { total: 0, page: 1, limit: 20, totalPages: 1 }
  const totalPages = pagination.totalPages || 1

  const { data: editUser } = useQuery({
    queryKey: ['user', editUserId],
    queryFn: () => api.get(`/security/users/${editUserId}`).then((r) => r.data.data),
    enabled: !!editUserId,
  })

  useEffect(() => {
    if (editUser) {
      editForm.reset({
        email: editUser.email || '',
        first_name_ar: editUser.first_name_ar || '',
        last_name_ar: editUser.last_name_ar || '',
        first_name_en: editUser.first_name_en || '',
        last_name_en: editUser.last_name_en || '',
        mobile: editUser.mobile || '',
        institution_id: editUser.institution_id ? String(editUser.institution_id) : '',
        department_id: editUser.department_id ? String(editUser.department_id) : '',
        status: editUser.status || 'ACTIVE',
        role_codes: (editUser.roles || []).map((r: any) => r.code),
      })
    }
  }, [editUser, editForm])

  const { data: roles } = useQuery({
    queryKey: ['roles'],
    queryFn: () => api.get('/security/roles').then((r) => r.data.data || []),
  })

  const { data: institutions } = useQuery({
    queryKey: ['institutions'],
    queryFn: () => api.get('/reference/institutions-registry').then((r) => r.data.data || []),
  })

  const createMutation = useMutation({
    mutationFn: (body: any) => api.post('/security/users', body),
    onSuccess: () => { toast.success(t('users.created')); queryClient.invalidateQueries({ queryKey: ['users'] }); setShowCreate(false); reset() },
    onError: (err: any) => toast.error(err.response?.data?.error || t('users.createFailed')),
  })

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: number; data: any }) => api.put(`/security/users/${id}`, data),
    onSuccess: () => { toast.success(t('users.updated')); queryClient.invalidateQueries({ queryKey: ['users'] }); setEditUserId(null) },
    onError: (err: any) => toast.error(err.response?.data?.error || t('users.updateFailed')),
  })

  function toggleRole(code: string) {
    const current = roleCodes || []
    if (current.includes(code)) setValue('role_codes', current.filter(c => c !== code), { shouldDirty: true })
    else setValue('role_codes', [...current, code], { shouldDirty: true })
  }

  function toggleEditRole(code: string) {
    const current = editRoleCodes || []
    if (current.includes(code)) editForm.setValue('role_codes', current.filter((c: string) => c !== code), { shouldDirty: true })
    else editForm.setValue('role_codes', [...current, code], { shouldDirty: true })
  }

  function onSearchChange(val: string) {
    setSearchQuery(val)
    setPage(1)
  }

  function handleSort(key: string) {
    if (sortKey === key) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc')
    } else {
      setSortKey(key)
      setSortDir('asc')
    }
    setPage(1)
  }

  return (
